{
  "name": "WebInsight AI",
  "description": "An advanced website analyzer powered by Gemini 3 Flash and Google Search Grounding to provide deep insights and summaries of any web URL."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface AnalysisResult {
  summary: string;
  sources: GroundingSource[];
}

export interface AnalysisState {
  isLoading: boolean;
  error: string | null;
  result: AnalysisResult | null;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, GroundingSource } from "../types";

export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Please visit and analyze the following website: ${url}. 
  Provide a detailed explanation of what this website is about, its primary purpose, its target audience, and its key features. 
  Structure the response clearly using Markdown.`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const summary = response.text || "No summary could be generated.";

    // Extract grounding sources
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || 'Source',
            uri: chunk.web.uri,
          });
        }
      });
    }

    return { summary, sources };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Failed to analyze the website. Please ensure the URL is correct and try again.");
  }
};

import React, { useState } from 'react';
import { analyzeWebsite } from '../services/geminiService';
import { AnalysisState } from '../types';

const AnalyzerCard: React.FC = () => {
  const [url, setUrl] = useState('siddarthacollegetimetable.bolt.host');
  const [state, setState] = useState<AnalysisState>({
    isLoading: false,
    error: null,
    result: null,
  });

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url) return;

    setState({ isLoading: true, error: null, result: null });

    try {
      const result = await analyzeWebsite(url);
      setState({ isLoading: false, error: null, result });
    } catch (err: any) {
      setState({ isLoading: false, error: err.message || "An unexpected error occurred", result: null });
    }
  };

  const formattedSummary = (text: string) => {
    // Basic markdown-to-html conversion for display purposes
    // In a real app we'd use react-markdown, but we'll stick to a clean textual approach here
    return text.split('\n').map((line, i) => {
      if (line.startsWith('# ')) return <h1 key={i} className="text-2xl font-bold mt-4 mb-2 text-blue-400">{line.replace('# ', '')}</h1>;
      if (line.startsWith('## ')) return <h2 key={i} className="text-xl font-bold mt-4 mb-2 text-blue-300">{line.replace('## ', '')}</h2>;
      if (line.startsWith('### ')) return <h3 key={i} className="text-lg font-semibold mt-3 mb-1 text-blue-200">{line.replace('### ', '')}</h3>;
      if (line.startsWith('* ') || line.startsWith('- ')) return <li key={i} className="ml-4 list-disc text-slate-300">{line.replace(/^[*|-]\s/, '')}</li>;
      return <p key={i} className="mb-3 text-slate-300 leading-relaxed">{line}</p>;
    });
  };

  return (
    <div className="max-w-4xl mx-auto mt-12 px-4">
      <div className="bg-slate-800/50 border border-slate-700 rounded-2xl overflow-hidden shadow-2xl backdrop-blur-sm">
        <div className="p-8 border-b border-slate-700 bg-slate-800/80">
          <h2 className="text-2xl font-bold text-white mb-2">Analyze Website</h2>
          <p className="text-slate-400 mb-6">Enter a URL to get an AI-powered summary and insights via Google Search grounding.</p>

          <form onSubmit={handleAnalyze} className="flex flex-col sm:flex-row gap-4">
            <div className="relative flex-grow">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <i className="fa-solid fa-globe text-slate-500"></i>
              </div>
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="example.com"
                className="block w-full pl-10 pr-4 py-3 bg-slate-900 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />
            </div>
            <button
              type="submit"
              disabled={state.isLoading}
              className={`px-8 py-3 rounded-xl font-bold text-white transition-all flex items-center justify-center space-x-2 ${
                state.isLoading 
                ? 'bg-slate-700 cursor-not-allowed' 
                : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 shadow-lg shadow-blue-500/20 active:scale-95'
              }`}
            >
              {state.isLoading ? (
                <>
                  <i className="fa-solid fa-circle-notch fa-spin"></i>
                  <span>Analyzing...</span>
                </>
              ) : (
                <>
                  <i className="fa-solid fa-magnifying-glass"></i>
                  <span>Analyze URL</span>
                </>
              )}
            </button>
          </form>
        </div>

        <div className="p-8 min-h-[200px]">
          {state.isLoading && (
            <div className="flex flex-col items-center justify-center space-y-4 py-12">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <i className="fa-solid fa-robot text-blue-500 animate-pulse"></i>
                </div>
              </div>
              <div className="text-center">
                <p className="text-white font-medium">Scanning the web...</p>
                <p className="text-slate-500 text-sm">Gemini is gathering data about {url}</p>
              </div>
            </div>
          )}

          {state.error && (
            <div className="bg-red-500/10 border border-red-500/20 rounded-xl p-6 flex items-start space-x-4">
              <i className="fa-solid fa-circle-exclamation text-red-500 mt-1"></i>
              <div>
                <h3 className="text-red-500 font-bold">Analysis Failed</h3>
                <p className="text-red-400/80 text-sm">{state.error}</p>
              </div>
            </div>
          )}

          {!state.isLoading && !state.error && !state.result && (
            <div className="flex flex-col items-center justify-center text-center space-y-4 py-12 opacity-50">
              <div className="w-20 h-20 bg-slate-900 rounded-full flex items-center justify-center">
                <i className="fa-solid fa-keyboard text-3xl text-slate-700"></i>
              </div>
              <p className="text-slate-400">Ready to provide deep insights for any URL.</p>
            </div>
          )}

          {state.result && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center space-x-2 mb-6">
                <div className="px-3 py-1 bg-green-500/10 text-green-400 text-xs font-bold rounded-full border border-green-500/20 flex items-center">
                  <span className="w-2 h-2 bg-green-500 rounded-full mr-2 animate-pulse"></span>
                  ANALYSIS COMPLETE
                </div>
                <div className="px-3 py-1 bg-blue-500/10 text-blue-400 text-xs font-bold rounded-full border border-blue-500/20">
                  GEMINI 3 FLASH
                </div>
              </div>

              <div className="prose prose-invert max-w-none">
                {formattedSummary(state.result.summary)}
              </div>

              {state.result.sources.length > 0 && (
                <div className="mt-12 pt-8 border-t border-slate-700">
                  <h3 className="text-white font-bold mb-4 flex items-center">
                    <i className="fa-solid fa-link mr-2 text-blue-400"></i>
                    Sources & Grounding
                  </h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {state.result.sources.map((source, i) => (
                      <a
                        key={i}
                        href={source.uri}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="p-3 bg-slate-900/50 border border-slate-700 rounded-lg hover:bg-slate-700 transition-colors group flex items-center"
                      >
                        <i className="fa-solid fa-file-lines text-slate-500 mr-3 group-hover:text-blue-400"></i>
                        <span className="text-sm text-slate-300 group-hover:text-white truncate">
                          {source.title}
                        </span>
                        <i className="fa-solid fa-arrow-up-right-from-square ml-auto text-xs text-slate-600 group-hover:text-blue-400"></i>
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AnalyzerCard;

{
  "name": "Siddartha College Timetable AI",
  "description": "Smart scheduling system with AI-powered conflict detection and substitution management.",
  "requestFramePermissions": []
}

export interface TimetableEntry {
  id: string;
  day: string;
  time: string;
  subject: string;
  faculty: string;
  room: string;
  type: 'Lecture' | 'Lab' | 'Seminar';
}

export interface SubstitutionResult {
  originalFaculty: string;
  suggestedSubstitute: string;
  reasoning: string;
}

export interface ConflictReport {
  type: 'Room' | 'Faculty' | 'Time';
  description: string;
  affectedEntries: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { TimetableEntry } from "../types";

export const detectConflicts = async (entries: TimetableEntry[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this college timetable for Siddartha College and identify any logical conflicts. 
  Conflicts include: 
  1. The same Faculty scheduled for two classes at the same time.
  2. The same Room occupied by two different subjects at the same time.

  Timetable Data: ${JSON.stringify(entries)}

  Return the analysis as a structured list of conflicts found.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          conflicts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING },
                description: { type: Type.STRING },
                severity: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const suggestSubstitution = async (subject: string, reason: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const model = 'gemini-3-flash-preview';

  const prompt = `At Siddartha College, a faculty member teaching "${subject}" is unavailable due to: ${reason}. 
  Suggest a suitable substitute from typical department profiles (CSE, ECE, IT) and explain why they are a good fit. 
  Include a brief plan for what the substitute should cover in this specific class.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text;
};

import React, { useState } from 'react';
import { TimetableEntry } from '../types';
import { detectConflicts, suggestSubstitution } from '../services/geminiService';

const MOCK_DATA: TimetableEntry[] = [
  { id: '1', day: 'Monday', time: '09:00 AM', subject: 'Data Structures', faculty: 'Dr. Ramesh', room: 'L-101', type: 'Lecture' },
  { id: '2', day: 'Monday', time: '10:00 AM', subject: 'Python Lab', faculty: 'Ms. Sridevi', room: 'Lab-1', type: 'Lab' },
  { id: '3', day: 'Monday', time: '11:00 AM', subject: 'Operating Systems', faculty: 'Prof. Arjun', room: 'L-204', type: 'Lecture' },
  { id: '4', day: 'Tuesday', time: '09:00 AM', subject: 'Java Programming', faculty: 'Mr. Kiran', room: 'L-101', type: 'Lecture' },
  { id: '5', day: 'Tuesday', time: '10:00 AM', subject: 'Digital Logic', faculty: 'Dr. Ramesh', room: 'L-302', type: 'Lecture' },
];

const TimetableBoard: React.FC = () => {
  const [entries, setEntries] = useState<TimetableEntry[]>(MOCK_DATA);
  const [selectedDay, setSelectedDay] = useState('Monday');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [subRequest, setSubRequest] = useState({ subject: '', reason: '' });
  const [subResponse, setSubResponse] = useState<string | null>(null);

  const handleConflictCheck = async () => {
    setIsAnalyzing(true);
    try {
      const result = await detectConflicts(entries);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubstitution = async () => {
    if (!subRequest.subject) return;
    setIsAnalyzing(true);
    try {
      const result = await suggestSubstitution(subRequest.subject, subRequest.reason);
      setSubResponse(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const filteredEntries = entries.filter(e => e.day === selectedDay);

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Side: Timetable View */}
        <div className="lg:col-span-2 space-y-6">
          <div className="glass rounded-3xl p-6 shadow-xl shadow-green-900/5">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <i className="fa-solid fa-calendar-day text-emerald-600"></i>
                Schedule View
              </h2>
              <div className="flex bg-white/50 p-1 rounded-xl gap-1">
                {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'].map(day => (
                  <button
                    key={day}
                    onClick={() => setSelectedDay(day)}
                    className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                      selectedDay === day 
                        ? 'bg-emerald-600 text-white shadow-md' 
                        : 'text-emerald-800 hover:bg-emerald-100'
                    }`}
                  >
                    {day.substring(0, 3)}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              {filteredEntries.map(entry => (
                <div key={entry.id} className="group relative bg-white/80 p-5 rounded-2xl border border-emerald-100 hover:border-emerald-300 transition-all hover:translate-x-1">
                  <div className="flex items-center justify-between">
                    <div className="flex gap-4 items-center">
                      <div className="w-14 h-14 bg-emerald-100 rounded-2xl flex flex-col items-center justify-center text-emerald-700">
                        <span className="text-xs font-bold uppercase">{entry.time.split(' ')[1]}</span>
                        <span className="text-sm font-black">{entry.time.split(' ')[0]}</span>
                      </div>
                      <div>
                        <h4 className="font-bold text-lg text-emerald-900">{entry.subject}</h4>
                        <p className="text-sm text-emerald-600 flex items-center gap-2">
                          <i className="fa-solid fa-user-tie text-xs"></i> {entry.faculty}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase mb-2 inline-block ${
                        entry.type === 'Lab' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'
                      }`}>
                        {entry.type}
                      </span>
                      <p className="text-sm font-medium text-emerald-500">
                        <i className="fa-solid fa-location-dot"></i> {entry.room}
                      </p>
                    </div>
                  </div>
                </div>
              ))}
              {filteredEntries.length === 0 && (
                <div className="text-center py-12 text-emerald-300 italic">No classes scheduled for this day.</div>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: AI Tools */}
        <div className="space-y-6">
          {/* Conflict Detector */}
          <div className="glass rounded-3xl p-6 shadow-xl border-emerald-200">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-triangle-exclamation text-amber-500"></i>
              AI Conflict Monitor
            </h3>
            <button
              onClick={handleConflictCheck}
              disabled={isAnalyzing}
              className="w-full py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold transition-all disabled:opacity-50"
            >
              {isAnalyzing ? <i className="fa-solid fa-circle-notch fa-spin"></i> : 'Run Deep Scan'}
            </button>
            {analysis && (
              <div className="mt-4 p-4 bg-white/50 rounded-xl border border-emerald-100">
                {analysis.conflicts && analysis.conflicts.length > 0 ? (
                  analysis.conflicts.map((c: any, i: number) => (
                    <div key={i} className="mb-2 text-sm">
                      <p className="font-bold text-red-600">● {c.type}</p>
                      <p className="text-slate-600">{c.description}</p>
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-green-600 font-medium">✨ All clear! No conflicts detected.</p>
                )}
              </div>
            )}
          </div>

          {/* Substitution Manager */}
          <div className="glass rounded-3xl p-6 shadow-xl border-blue-200">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-user-gear text-blue-500"></i>
              Smart Substitution
            </h3>
            <div className="space-y-3">
              <input
                type="text"
                placeholder="Subject (e.g. Data Structures)"
                className="w-full px-4 py-2 rounded-lg bg-white/80 border border-emerald-100 focus:outline-emerald-500 text-sm"
                value={subRequest.subject}
                onChange={e => setSubRequest({...subRequest, subject: e.target.value})}
              />
              <textarea
                placeholder="Reason for leave..."
                className="w-full px-4 py-2 rounded-lg bg-white/80 border border-emerald-100 focus:outline-emerald-500 text-sm h-20"
                value={subRequest.reason}
                onChange={e => setSubRequest({...subRequest, reason: e.target.value})}
              />
              <button
                onClick={handleSubstitution}
                disabled={isAnalyzing}
                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all disabled:opacity-50"
              >
                Find Replacement
              </button>
            </div>
            {subResponse && (
              <div className="mt-4 p-4 bg-blue-50/80 rounded-xl border border-blue-100 text-xs leading-relaxed text-blue-900 max-h-60 overflow-y-auto scrollbar-hide">
                <p className="font-bold mb-2">AI Suggestion:</p>
                <div dangerouslySetInnerHTML={{ __html: subResponse.replace(/\n/g, '<br/>') }} />
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export default TimetableBoard;

