// Detect logical conflicts in the provided timetable data
export const detectConflicts = async (entries: TimetableEntry[]) => {
  // Use direct process.env.API_KEY with named parameter initialization
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this college timetable for Siddartha College and identify any logical conflicts. 
  Conflicts include: 
  1. The same Faculty scheduled for two classes at the same time.
  2. The same Room occupied by two different subjects at the same time.

  Timetable Data: ${JSON.stringify(entries)}

  Return the analysis as a structured list of conflicts found.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          conflicts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING },
                description: { type: Type.STRING },
                severity: { type: Type.STRING }
              },
              required: ["type", "description"]
            }
          }
        },
        required: ["conflicts"]
      }
    }
  });

  // Access text property directly
  return JSON.parse(response.text || '{"conflicts": []}');
};

// Suggest a suitable faculty replacement for a given subject and reason
export const suggestSubstitution = async (subject: string, reason: string) => {
  // Use direct process.env.API_KEY with named parameter initialization
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `At Siddartha College, a faculty member teaching "${subject}" is unavailable due to: ${reason}. 
  Suggest a suitable substitute from typical department profiles (CSE, ECE, IT) and explain why they are a good fit. 
  Include a brief plan for what the substitute should cover in this specific class.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  // Access text property directly
  return response.text;
};

// Analyze a website URL using Google Search grounding to provide summaries and sources
export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Summarize the content and key details of the website at this URL: ${url}`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const summary = response.text || "No summary was generated.";
  const sources: { uri: string; title: string }[] = [];

  // Extract grounding information for Google Search results
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    for (const chunk of chunks) {
      if (chunk.web) {
        sources.push({
          uri: chunk.web.uri || "",
          title: chunk.web.title || "Reference",
        });
      }
    }
  }

  return { summary, sources };
};

