import React, { useState, useEffect } from 'react';
import { TimetableEntry } from '../types';
import { detectConflicts, suggestSubstitution } from '../services/geminiService';
import { getTimetable } from '../services/dataStore';

const TimetableBoard: React.FC = () => {
  const [entries, setEntries] = useState<TimetableEntry[]>([]);
  const [selectedDay, setSelectedDay] = useState('Monday');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [subRequest, setSubRequest] = useState({ subject: '', reason: '' });
  const [subResponse, setSubResponse] = useState<string | null>(null);

  useEffect(() => {
    // Load data from persistent store
    const stored = getTimetable();
    if (stored.length > 0) {
      setEntries(stored);
    } else {
      // Fallback or handle empty state
      setEntries([
        { id: '1', day: 'Monday', time: '09:00 AM', subject: 'Data Structures', faculty: 'Dr. Ramesh', room: 'L-101', type: 'Lecture' },
        { id: '2', day: 'Monday', time: '10:00 AM', subject: 'Python Lab', faculty: 'Ms. Sridevi', room: 'Lab-1', type: 'Lab' },
      ]);
    }
  }, []);

  const handleConflictCheck = async () => {
    setIsAnalyzing(true);
    try {
      const result = await detectConflicts(entries);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubstitution = async () => {
    if (!subRequest.subject) return;
    setIsAnalyzing(true);
    try {
      const result = await suggestSubstitution(subRequest.subject, subRequest.reason);
      setSubResponse(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const filteredEntries = entries.filter(e => e.day === selectedDay);

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Side: Timetable View */}
        <div className="lg:col-span-2 space-y-6">
          <div className="glass rounded-3xl p-6 shadow-xl shadow-green-900/5">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <i className="fa-solid fa-calendar-day text-emerald-600"></i>
                Schedule View
              </h2>
              <div className="flex bg-white/50 p-1 rounded-xl gap-1 overflow-x-auto scrollbar-hide">
                {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'].map(day => (
                  <button
                    key={day}
                    onClick={() => setSelectedDay(day)}
                    className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all whitespace-nowrap ${
                      selectedDay === day 
                        ? 'bg-emerald-600 text-white shadow-md' 
                        : 'text-emerald-800 hover:bg-emerald-100'
                    }`}
                  >
                    {day.substring(0, 3)}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              {filteredEntries.map(entry => (
                <div key={entry.id} className="group relative bg-white/80 p-5 rounded-2xl border border-emerald-100 hover:border-emerald-300 transition-all hover:translate-x-1">
                  <div className="flex items-center justify-between">
                    <div className="flex gap-4 items-center">
                      <div className="w-14 h-14 bg-emerald-100 rounded-2xl flex flex-col items-center justify-center text-emerald-700">
                        <span className="text-xs font-bold uppercase">{entry.time.split(' ')[1]}</span>
                        <span className="text-sm font-black">{entry.time.split(' ')[0]}</span>
                      </div>
                      <div>
                        <h4 className="font-bold text-lg text-emerald-900">{entry.subject}</h4>
                        <p className="text-sm text-emerald-600 flex items-center gap-2">
                          <i className="fa-solid fa-user-tie text-xs"></i> {entry.faculty}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase mb-2 inline-block ${
                        entry.type === 'Lab' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'
                      }`}>
                        {entry.type}
                      </span>
                      <p className="text-sm font-medium text-emerald-500">
                        <i className="fa-solid fa-location-dot"></i> {entry.room}
                      </p>
                    </div>
                  </div>
                </div>
              ))}
              {filteredEntries.length === 0 && (
                <div className="text-center py-12 text-emerald-300 italic">No classes scheduled for this day.</div>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: AI Tools */}
        <div className="space-y-6">
          {/* Conflict Detector */}
          <div className="glass rounded-3xl p-6 shadow-xl border-emerald-200">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-triangle-exclamation text-amber-500"></i>
              AI Conflict Monitor
            </h3>
            <button
              onClick={handleConflictCheck}
              disabled={isAnalyzing}
              className="w-full py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold transition-all disabled:opacity-50"
            >
              {isAnalyzing ? <i className="fa-solid fa-circle-notch fa-spin"></i> : 'Run Deep Scan'}
            </button>
            {analysis && (
              <div className="mt-4 p-4 bg-white/50 rounded-xl border border-emerald-100">
                {analysis.conflicts && analysis.conflicts.length > 0 ? (
                  analysis.conflicts.map((c: any, i: number) => (
                    <div key={i} className="mb-2 text-sm">
                      <p className="font-bold text-red-600">● {c.type}</p>
                      <p className="text-slate-600">{c.description}</p>
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-green-600 font-medium">✨ All clear! No conflicts detected.</p>
                )}
              </div>
            )}
          </div>

          {/* Substitution Manager */}
          <div className="glass rounded-3xl p-6 shadow-xl border-blue-200">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-user-gear text-blue-500"></i>
              Smart Substitution
            </h3>
            <div className="space-y-3">
              <input
                type="text"
                placeholder="Subject (e.g. Data Structures)"
                className="w-full px-4 py-2 rounded-lg bg-white/80 border border-emerald-100 focus:outline-emerald-500 text-sm"
                value={subRequest.subject}
                onChange={e => setSubRequest({...subRequest, subject: e.target.value})}
              />
              <textarea
                placeholder="Reason for leave..."
                className="w-full px-4 py-2 rounded-lg bg-white/80 border border-emerald-100 focus:outline-emerald-500 text-sm h-20"
                value={subRequest.reason}
                onChange={e => setSubRequest({...subRequest, reason: e.target.value})}
              />
              <button
                onClick={handleSubstitution}
                disabled={isAnalyzing}
                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all disabled:opacity-50"
              >
                Find Replacement
              </button>
            </div>
            {subResponse && (
              <div className="mt-4 p-4 bg-blue-50/80 rounded-xl border border-blue-100 text-xs leading-relaxed text-blue-900 max-h-60 overflow-y-auto scrollbar-hide">
                <p className="font-bold mb-2">AI Suggestion:</p>
                <div dangerouslySetInnerHTML={{ __html: subResponse.replace(/\n/g, '<br/>') }} />
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export default TimetableBoard;

