import { GoogleGenAI, Type } from "@google/genai";
import { TimetableEntry, AnalysisResult } from "../types";

// Detect logical conflicts specific to Pharmacy College needs
export const detectConflicts = async (entries: TimetableEntry[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this Pharmacy College timetable (KVSR SCOPS) and identify any logical conflicts. 
  Specific considerations for Pharmacy:
  1. Labs usually last 3-4 hours; check for overlaps in long durations.
  2. Pharm.D students have clinical rotations; ensure no room overlaps during clinic hours.
  3. Faculty cannot be in a Lecture and a Lab at the same time.
  4. Same Lab room cannot host two different subjects simultaneously.

  Timetable Data: ${JSON.stringify(entries)}

  Return a structured JSON with a list of conflicts.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          conflicts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, description: 'Room, Faculty, or Time conflict' },
                description: { type: Type.STRING },
                severity: { type: Type.STRING, description: 'High, Medium, or Low' }
              },
              required: ["type", "description"]
            }
          }
        },
        required: ["conflicts"]
      }
    }
  });

  return JSON.parse(response.text || '{"conflicts": []}');
};

// Suggest a suitable faculty replacement with Pharmacy specialization logic
export const suggestSubstitution = async (subject: string, reason: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `A faculty member teaching "${subject}" at KVSR Siddhartha College of Pharmacy is unavailable due to: ${reason}. 
  Pharmacy specializations include: Pharmaceutics, Pharmacology, Pharmaceutical Analysis, Pharmacognosy, and Pharmacy Practice.

  Please:
  1. Suggest which department profile should provide the substitute.
  2. Suggest a specific profile matching the expertise required for "${subject}".
  3. Provide a brief 1-hour class plan for the substitute.

  Return the response in a clear, professional academic format.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text;
};

// Analyze a website URL for college references
export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze and summarize this pharmacy related URL: ${url}. Provide context relative to KVSR SCOPS or generic pharmaceutical education.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const summary = response.text || "No summary was generated.";
  const sources: { uri: string; title: string }[] = [];

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    for (const chunk of chunks) {
      if (chunk.web) {
        sources.push({
          uri: chunk.web.uri || "",
          title: chunk.web.title || "Reference",
        });
      }
    }
  }

  return { summary, sources };
};

