const LoginForm: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const settings = getSettings();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Use stored admin credentials
    if (username === settings.adminUsername && password === settings.adminPassword) {
      setSession('dummy_token_' + Date.now());
      onLogin();
    } else {
      setError('Invalid credentials. Access denied.');
    }
  };

  const isGoogleConfigured = settings.googleLoginEnabled && settings.googleClientId && settings.googleClientSecret;

  return (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl border-emerald-100 text-center animate-in zoom-in duration-300">
        <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-200 mx-auto mb-6">
          <i className="fa-solid fa-shield-halved text-white text-2xl"></i>
        </div>

        <h2 className="text-2xl font-black text-emerald-900 mb-2">Restricted Access</h2>
        <p className="text-emerald-600 text-sm mb-8 font-medium italic">Please authorize to manage campus data</p>

        <form onSubmit={handleLogin} className="space-y-4 text-left">
          {error && <p className="text-xs text-red-500 font-bold bg-red-50 p-3 rounded-lg border border-red-100 mb-4">{error}</p>}

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Username</label>
            <input 
              type="text" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500" 
              value={username}
              onChange={e => setUsername(e.target.value)}
              required
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Password</label>
            <input 
              type="password" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500" 
              value={password}
              onChange={e => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit"
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-bold transition-all shadow-lg shadow-emerald-200 mt-4 active:scale-95"
          >
            Authenticate
          </button>
        </form>

        {isGoogleConfigured && (
          <div className="mt-8 pt-8 border-t border-emerald-100">
            <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest mb-4">Or sign in with SSO</p>
            <button 
              onClick={() => alert('SSO Flow Initiated for approved faculty emails.')}
              className="w-full py-4 bg-white hover:bg-emerald-50 text-emerald-900 rounded-2xl font-bold transition-all border border-emerald-100 flex items-center justify-center gap-3 shadow-sm"
            >
              <i className="fa-brands fa-google text-red-500"></i>
              Faculty Google Login
            </button>
          </div>
        )}

        <p className="mt-8 text-[10px] text-emerald-300 font-bold uppercase tracking-tight">
          Session Encryption Active • Siddartha IT Dept
        </p>
      </div>
    </div>
  );
};

