                  <button 
                    onClick={() => {
                      const newClass: ClassRoom = { id: Date.now().toString(), name: 'Room TBD', building: 'Main' };
                      const updated = [...classes, newClass];
                      setClasses(updated);
                      saveClasses(updated);
                    }}
                    className="px-4 py-2 bg-emerald-600 text-white rounded-xl font-bold text-sm"
                  >
                    + Add Room
                  </button>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                  {classes.map((c) => (
                    <div key={c.id} className="bg-white/50 p-6 rounded-2xl border border-emerald-50 text-center">
