                        className="bg-transparent text-lg font-black text-center border-none w-full mb-1 focus:ring-0" 
                        value={c.name}
                        onChange={(e) => {
                          const updated = classes.map(cl => cl.id === c.id ? {...cl, name: e.target.value} : cl);
                          setClasses(updated);
                          saveClasses(updated);
                        }}
                      />
                       <button 
                           onClick={() => {
                            const updated = classes.filter(cl => cl.id !== c.id);
                            setClasses(updated);
                            saveClasses(updated);
                          }}
                          className="text-xs font-bold text-red-400 mt-4 hover:underline"
                        >
                          Remove
                        </button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'settings' && (
              <div className="space-y-8">
                <div>
                  <h2 className="text-xl font-bold text-emerald-900 mb-6">Security & Auth Settings</h2>

                  <div className="space-y-6 max-w-lg">
                    {/* Admin Credentials Settings */}
                    <div className="space-y-4 p-4 bg-emerald-50/50 rounded-2xl border border-emerald-100">
                      <p className="font-bold text-emerald-900">Administrative Login</p>
                      <div className="space-y-3">
                        <div>
                          <p className="text-[10px] font-black text-emerald-600 uppercase mb-1">Admin Username</p>
                          <input 
                            type="text"
                            className="w-full p-3 bg-white/50 rounded-xl border border-emerald-100 text-sm focus:outline-emerald-500"
                            value={settings.adminUsername}
                            onChange={(e) => {
                              const updated = {...settings, adminUsername: e.target.value};
                              setSettings(updated);
                              saveSettings(updated);
                            }}
                          />
                        </div>
                        <div>
                          <p className="text-[10px] font-black text-emerald-600 uppercase mb-1">Admin Password</p>
                          <input 
                            type="password"
                            className="w-full p-3 bg-white/50 rounded-xl border border-emerald-100 text-sm focus:outline-emerald-500"
                            value={settings.adminPassword}
                            onChange={(e) => {
                              const updated = {...settings, adminPassword: e.target.value};
                              setSettings(updated);
                              saveSettings(updated);
                            }}
                          />
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center justify-between p-4 bg-white/50 rounded-2xl border border-emerald-50">
                      <div>
                        <p className="font-bold text-emerald-900">Google OAuth Login</p>
                        <p className="text-xs text-emerald-500">Allow faculty to sign in using G-Suite</p>
                      </div>
                      <button 
                        onClick={() => {
                          const updated = {...settings, googleLoginEnabled: !settings.googleLoginEnabled};
                          setSettings(updated);
                          saveSettings(updated);
                        }}
                        className={`w-12 h-6 rounded-full transition-colors relative ${settings.googleLoginEnabled ? 'bg-emerald-500' : 'bg-slate-300'}`}
                      >
                        <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${settings.googleLoginEnabled ? 'left-7' : 'left-1'}`}></div>
                      </button>
                    </div>

                    <div className="space-y-4">
                      <p className="text-sm font-bold text-emerald-900">Approved Faculty Emails</p>
                      <textarea 
                        className="w-full h-32 p-4 bg-white/50 rounded-2xl border border-emerald-100 text-sm focus:outline-emerald-500"
                        placeholder="Enter emails separated by commas..."
                        value={settings.approvedEmails.join(', ')}
                        onChange={(e) => {
                          const emails = e.target.value.split(',').map(em => em.trim()).filter(Boolean);
                          const updated = {...settings, approvedEmails: emails};
                          setSettings(updated);
                          saveSettings(updated);
                        }}
                      />
                    </div>

                    <div className="grid grid-cols-1 gap-4">
                      <div>
                        <p className="text-xs font-bold text-emerald-600 mb-2 uppercase">OAuth Client ID</p>
                        <input 
                          type="password"
                          className="w-full p-3 bg-white/50 rounded-xl border border-emerald-100 text-sm"
                          value={settings.googleClientId}
                          onChange={(e) => {
                            const updated = {...settings, googleClientId: e.target.value};
                            setSettings(updated);
                            saveSettings(updated);
                          }}
                        />
                      </div>
                      <div>
                        <p className="text-xs font-bold text-emerald-600 mb-2 uppercase">OAuth Client Secret</p>
                        <input 
                          type="password"
                          className="w-full p-3 bg-white/50 rounded-xl border border-emerald-100 text-sm"
                          value={settings.googleClientSecret}
                          onChange={(e) => {
                            const updated = {...settings, googleClientSecret: e.target.value};
                            setSettings(updated);
                            saveSettings(updated);
                          }}
                        />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

