import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { TimetableEntry } from '../types';
import { detectConflicts, suggestSubstitution } from '../services/geminiService';
import { getTimetable } from '../services/dataStore';

const TimetableBoard: React.FC = () => {
  const [entries, setEntries] = useState<TimetableEntry[]>([]);
  const [selectedDay, setSelectedDay] = useState('Monday');
  const [selectedCourse, setSelectedCourse] = useState<string>('All');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [subRequest, setSubRequest] = useState({ subject: '', reason: '' });
  const [subResponse, setSubResponse] = useState<string | null>(null);

  useEffect(() => {
    const stored = getTimetable();
    if (stored.length > 0) {
      setEntries(stored);
    } else {
      setEntries([
        { id: '1', day: 'Monday', time: '09:00 AM', subject: 'Pharmaceutics-I', faculty: 'Dr. Ramesh', room: 'L-101', course: 'B.Pharm', type: 'Lecture' },
        { id: '2', day: 'Monday', time: '10:00 AM', subject: 'Human Anatomy', faculty: 'Ms. Sridevi', room: 'Lab-1', course: 'B.Pharm', type: 'Lab' },
        { id: '3', day: 'Monday', time: '11:00 AM', subject: 'Clinical Research', faculty: 'Prof. Arjun', room: 'L-204', course: 'Pharm.D', type: 'Seminar' },
      ]);
    }
  }, []);

  const handleConflictCheck = async () => {
    setIsAnalyzing(true);
    try {
      const result = await detectConflicts(entries);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubstitution = async () => {
    if (!subRequest.subject) return;
    setIsAnalyzing(true);
    try {
      const result = await suggestSubstitution(subRequest.subject, subRequest.reason);
      setSubResponse(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const filteredEntries = entries.filter(e => 
    e.day === selectedDay && (selectedCourse === 'All' || e.course === selectedCourse)
  );

  return (
    <div className="max-w-7xl mx-auto px-4 py-16">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

        {/* Left Side: Timetable View (Col 8) */}
        <div className="lg:col-span-8 space-y-8">
          <div className="glass rounded-[2.5rem] p-10 shadow-2xl shadow-emerald-900/5 relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-100/50 rounded-full -mr-16 -mt-16 blur-2xl"></div>

            <div className="flex flex-col md:flex-row items-center justify-between mb-10 gap-6">
              <div>
                <h2 className="text-3xl font-black text-emerald-900 flex items-center gap-3">
                  <i className="fa-solid fa-clock-rotate-left text-emerald-500"></i>
                  Active Schedule
                </h2>
                <p className="text-xs font-bold text-emerald-600 uppercase tracking-widest mt-1">Real-time Session Tracking</p>
              </div>

              <div className="flex flex-wrap items-center bg-white/40 p-1.5 rounded-2xl gap-2 backdrop-blur-md border border-emerald-50/50">
                {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'].map(day => (
                  <button
                    key={day}
                    onClick={() => setSelectedDay(day)}
                    className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                      selectedDay === day 
                        ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/30' 
                        : 'text-emerald-800 hover:bg-emerald-100'
                    }`}
                  >
                    {day.substring(0, 3)}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-2 mb-8 overflow-x-auto scrollbar-hide pb-2">
              {['All', 'B.Pharm', 'Pharm.D', 'Pharm.D (PB)', 'M.Pharm'].map(course => (
                 <button
                   key={course}
                   onClick={() => setSelectedCourse(course)}
                   className={`px-4 py-2 rounded-full text-[9px] font-bold border transition-all whitespace-nowrap ${
                    selectedCourse === course 
                      ? 'bg-emerald-100 border-emerald-300 text-emerald-700' 
                      : 'border-emerald-100 text-emerald-400 hover:border-emerald-200'
                   }`}
                 >
                   {course}
                 </button>
              ))}
            </div>

            <div className="space-y-5">
              {filteredEntries.map(entry => (
                <div key={entry.id} className="group relative glass-dark p-6 rounded-[2rem] border-white/40 hover:border-emerald-400/30 transition-all hover:translate-x-2 shadow-sm hover:shadow-md">
                  <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                    <div className="flex gap-5 items-center">
                      <div className="w-16 h-16 bg-white rounded-[1.25rem] shadow-inner flex flex-col items-center justify-center text-emerald-800 border border-emerald-50">
                        <span className="text-[10px] font-black uppercase leading-none mb-1 text-emerald-400">
                          {entry.time.includes(' ') ? entry.time.split(' ')[1] : ''}
                        </span>
                        <span className="text-lg font-black">
                          {entry.time.includes(' ') ? entry.time.split(' ')[0] : entry.time}
                        </span>
                      </div>
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                           <span className="text-[9px] font-black text-emerald-400 uppercase tracking-tighter">{entry.course}</span>
                           <span className="w-1 h-1 rounded-full bg-emerald-200"></span>
                           <span className="text-[9px] font-bold text-emerald-500 uppercase">{entry.type}</span>
                        </div>
                        <h4 className="font-black text-xl text-emerald-900 leading-tight mb-1">{entry.subject}</h4>
                        <p className="text-xs font-bold text-emerald-600 flex items-center gap-2">
                          <i className="fa-solid fa-user-tie text-[10px]"></i> {entry.faculty}
                        </p>
                      </div>
                    </div>
                    <div className="text-left sm:text-right bg-emerald-50/50 sm:bg-transparent p-3 sm:p-0 rounded-xl w-full sm:w-auto">
                      <p className="text-sm font-black text-emerald-800 mb-1">
                        <i className="fa-solid fa-location-dot mr-1.5 text-emerald-400"></i> {entry.room}
                      </p>
                      <p className="text-[9px] font-bold text-emerald-400 uppercase tracking-widest">Building A-Wing</p>
                    </div>
                  </div>
                </div>
              ))}
              {filteredEntries.length === 0 && (
                <div className="flex flex-col items-center justify-center py-24 text-center">
                   <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mb-4 border border-emerald-100">
                      <i className="fa-solid fa-calendar-xmark text-emerald-200 text-3xl"></i>
                   </div>
                   <p className="text-emerald-300 font-bold italic">No sessions found for this selection.</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: AI Tools (Col 4) */}
        <div className="lg:col-span-4 space-y-10">
          {/* Conflict Detector */}
          <div className="glass rounded-[2.5rem] p-8 shadow-2xl border-emerald-100 group transition-all hover:shadow-emerald-900/10">
            <div className="flex items-center gap-3 mb-6">
               <div className="w-10 h-10 bg-amber-50 rounded-xl flex items-center justify-center text-amber-500 text-lg">
                  <i className="fa-solid fa-shield-virus"></i>
               </div>
               <div>
                  <h3 className="text-lg font-black text-emerald-900">AI Safety Monitor</h3>
                  <p className="text-[9px] font-bold text-emerald-400 uppercase">Heuristic Scan Engine</p>
               </div>
            </div>

            <button
              onClick={handleConflictCheck}
              disabled={isAnalyzing}
              className="w-full py-4 bg-emerald-700 hover:bg-emerald-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest transition-all disabled:opacity-50 active:scale-95 shadow-lg shadow-emerald-900/20"
            >
              {isAnalyzing ? <i className="fa-solid fa-dna fa-spin mr-2"></i> : <i className="fa-solid fa-bolt mr-2"></i>}
              {isAnalyzing ? 'Analyzing Matrix...' : 'Run Conflict Audit'}
            </button>

            {analysis && (
              <div className="mt-6 p-5 glass-dark rounded-2xl border-emerald-100 animate-in zoom-in-95 duration-300">
                {analysis.conflicts && analysis.conflicts.length > 0 ? (
                  <div className="space-y-4">
                    {analysis.conflicts.map((c: any, i: number) => (
                      <div key={i} className="flex gap-3 items-start border-b border-emerald-100/50 pb-3 last:border-0">
                        <span className={`mt-1 flex-shrink-0 w-2 h-2 rounded-full ${c.severity === 'High' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]' : 'bg-amber-500'}`}></span>
                        <div>
                          <p className="text-[10px] font-black text-emerald-900 uppercase">
                            {typeof c.type === 'string' ? c.type : 'Issue'}
                          </p>
                          <p className="text-[11px] font-medium text-emerald-600/80 leading-relaxed">
                            {typeof c.description === 'string' ? c.description : 'Unknown logical conflict detected.'}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="flex items-center gap-3 text-emerald-600 py-2">
                    <i className="fa-solid fa-circle-check text-lg"></i>
                    <p className="text-xs font-bold">Schedule Integrity Verified.</p>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Substitution Manager */}
          <div className="glass rounded-[2.5rem] p-8 shadow-2xl border-emerald-100 group transition-all hover:shadow-emerald-900/10">
             <div className="flex items-center gap-3 mb-6">
               <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-500 text-lg">
                  <i className="fa-solid fa-user-nurse"></i>
               </div>
               <div>
                  <h3 className="text-lg font-black text-emerald-900">Faculty Substitute</h3>
                  <p className="text-[9px] font-bold text-emerald-400 uppercase">Specialization Matching</p>
               </div>
            </div>

            <div className="space-y-4">
              <div className="relative">
