            {subResponse && (
              <div className="mt-6 p-5 bg-emerald-900 rounded-[1.5rem] text-[11px] leading-relaxed text-emerald-50 border border-emerald-700 shadow-inner max-h-72 overflow-y-auto scrollbar-hide animate-in slide-in-from-top-4 duration-300">
