                  <i className="fa-solid fa-robot text-emerald-300"></i>
                  <span className="font-black uppercase tracking-widest">AI Recommendation</span>
                </div>
                <div className="prose-invert" dangerouslySetInnerHTML={{ __html: String(subResponse).replace(/\n/g, '<br/>') }} />
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

