    { id: '3', day: 'Tuesday', time: '11:00 AM', subject: 'Pharmacognosy', faculty: 'Prof. Arjun', room: 'L-204', course: 'Pharm.D', type: 'Lecture' },
    { id: '4', day: 'Wednesday', time: '02:00 PM', subject: 'Clinical Pharmacy', faculty: 'Dr. Kavitha', room: 'Clinic-A', course: 'Pharm.D', type: 'Clinic' },
];

let state: AppState = {
    view: 'dashboard',
    isLoggedIn: localStorage.getItem('kvsr_admin_session') === 'true',
    selectedDay: 'Monday',
    selectedCourse: 'All',
    timetable: JSON.parse(localStorage.getItem(STORAGE_KEY) || JSON.stringify(defaultTimetable)),
    isAiBusy: false,
    aiResult: null,
    urlAnalysis: null
};

const saveState = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state.timetable));
};

/**
 * GEMINI API SERVICES
 */
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function detectConflicts() {
    state.isAiBusy = true;
    state.aiResult = { type: 'conflict', data: null };
    render();

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `As a Pharmacy College scheduler, check for overlaps in this timetable: ${JSON.stringify(state.timetable)}. Labs are 3 hours. Return JSON list of conflicts.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        conflicts: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    title: { type: Type.STRING },
                                    desc: { type: Type.STRING },
                                    severity: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
        });
        state.aiResult = { type: 'conflict', data: JSON.parse(response.text).conflicts };
    } catch (e) {
        console.error(e);
        state.aiResult = { type: 'conflict', error: "AI Scan Failed" };
    } finally {
        state.isAiBusy = false;
        render();
    }
}

async function analyzeUrl(url: string) {
    state.isAiBusy = true;
    state.urlAnalysis = null;
    render();

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `Analyze this pharmacy college related URL: ${url}. Provide a high-level summary of academic offerings or news mentioned.`,
            config: { tools: [{ googleSearch: {} }] }
        });

        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
        state.urlAnalysis = {
            text: response.text,
            sources: sources.filter((s: any) => s.web).map((s: any) => ({ uri: s.web.uri, title: s.web.title }))
        };
    } catch (e) {
        state.urlAnalysis = { error: "Failed to gather web data." };
    } finally {
        state.isAiBusy = false;
        render();
    }
}

