import { GoogleGenAI, Type } from "@google/genai";

/**
 * STATE DEFINITIONS
 */
interface TimeSlot {
    start: string;
    end: string;
}

interface TimetableEntry {
    id: string;
    day: string;
    periodIndex: number;
    subject: string;
    faculty: string;
    room: string;
    course: string;
    type: 'Lecture' | 'Lab' | 'Clinical';
}

interface Staff {
    id: string;
    name: string;
    dept: 'Pharmaceutics' | 'Pharmacology' | 'Analysis' | 'Pharmacognosy' | 'Practice';
    email: string;
}

interface AppSettings {
    daysPerWeek: number;
    periodsPerDay: number;
    periodTimes: TimeSlot[];
    googleLoginEnabled: boolean;
    approvedEmails: string[];
    oauthClientId: string;
    oauthClientSecret: string;
    adminUser: string;
    adminPass: string; // Stored in plain localstorage for demo, hash in real world
}

interface AppState {
    view: 'home' | 'admin' | 'analyzer';
    isLoggedIn: boolean;
    selectedDay: string;
    selectedCourse: string;
    settings: AppSettings;
    timetable: TimetableEntry[];
    staff: Staff[];
    isAiBusy: boolean;
    aiResult: any;
}

/**
 * INITIALIZATION & STORAGE
 */
const STORAGE_KEYS = {
    SETTINGS: 'kvsc_settings_v3',
    TIMETABLE: 'kvsc_timetable_v3',
    STAFF: 'kvsc_staff_v3',
    AUTH: 'kvsc_auth_v3'
};

const defaultSettings: AppSettings = {
    daysPerWeek: 5,
    periodsPerDay: 7,
    periodTimes: [
        { start: '09:00 AM', end: '10:00 AM' },
        { start: '10:00 AM', end: '11:00 AM' },
        { start: '11:00 AM', end: '12:00 PM' },
        { start: '12:00 PM', end: '01:00 PM' },
        { start: '02:00 PM', end: '03:00 PM' },
        { start: '03:00 PM', end: '04:00 PM' },
        { start: '04:00 PM', end: '05:00 PM' }
    ],
    googleLoginEnabled: false,
    approvedEmails: [],
    oauthClientId: '',
    oauthClientSecret: '',
    adminUser: 'admin',
    adminPass: 'password123'
};

let state: AppState = {
    view: 'home',
    isLoggedIn: localStorage.getItem(STORAGE_KEYS.AUTH) === 'true',
    selectedDay: 'Monday',
    selectedCourse: 'B.Pharm',
    settings: JSON.parse(localStorage.getItem(STORAGE_KEYS.SETTINGS) || JSON.stringify(defaultSettings)),
    timetable: JSON.parse(localStorage.getItem(STORAGE_KEYS.TIMETABLE) || '[]'),
    staff: JSON.parse(localStorage.getItem(STORAGE_KEYS.STAFF) || '[]'),
    isAiBusy: false,
    aiResult: null
};

const save = () => {
    localStorage.setItem(STORAGE_KEYS.SETTINGS, JSON.stringify(state.settings));
    localStorage.setItem(STORAGE_KEYS.TIMETABLE, JSON.stringify(state.timetable));
    localStorage.setItem(STORAGE_KEYS.STAFF, JSON.stringify(state.staff));
};

/**
 * AI SERVICES
 */
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function runConflictScan() {
    state.isAiBusy = true;
    render();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `As an academic auditor for KVSR Siddhartha College of Pharmacy, check these sessions for overlaps. 
            Remember: Lab sessions occupy multiple periods. 
            Schedule: ${JSON.stringify(state.timetable)}. 
            Context: Staff cannot be in two places at once. Labs need specific equipment rooms.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        conflicts: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    title: { type: Type.STRING },
                                    reason: { type: Type.STRING },
                                    severity: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
        });
        state.aiResult = { type: 'conflict', data: JSON.parse(response.text).conflicts };
    } catch (e) {
        state.aiResult = { type: 'error', msg: 'AI Scan Interrupted' };
    } finally {
        state.isAiBusy = false;
        render();
    }
}

