/**
 * GLOBAL ACTIONS
 */
(window as any).setView = (v: any) => { state.view = v; render(); };
(window as any).setDay = (d: string) => { state.selectedDay = d; render(); };
(window as any).setCourse = (c: string) => { state.selectedCourse = c; render(); };

(window as any).handleLogin = (e: Event) => {
    e.preventDefault();
    const u = (document.getElementById('adminUser') as HTMLInputElement).value;
    const p = (document.getElementById('adminPass') as HTMLInputElement).value;

    if (u === state.settings.adminUser && p === state.settings.adminPass) {
        state.isLoggedIn = true;
        localStorage.setItem(STORAGE_KEYS.AUTH, 'true');
        render();
    } else {
        alert('Invalid Academic Credentials.');
    }
};

(window as any).handleLogout = () => {
    state.isLoggedIn = false;
    localStorage.removeItem(STORAGE_KEYS.AUTH);
    render();
};

(window as any).updateSetting = (key: keyof AppSettings, val: any) => {
    (state.settings as any)[key] = val;
    save();
    render();
};

(window as any).toggleSetting = (key: keyof AppSettings) => {
    (state.settings as any)[key] = !(state.settings as any)[key];
    save();
    render();
};

(window as any).addEntry = () => {
    const newE: TimetableEntry = {
        id: Date.now().toString(),
        day: state.selectedDay,
        periodIndex: 0,
        subject: 'New Subject',
        faculty: 'Faculty Name',
        room: 'L-101',
        course: state.selectedCourse === 'All' ? 'B.Pharm' : state.selectedCourse,
        type: 'Lecture'
    };
    state.timetable.push(newE);
    save();
    render();
};

(window as any).updateEntry = (idx: number, key: keyof TimetableEntry, val: any) => {
    (state.timetable[idx] as any)[key] = val;
    save();
};

(window as any).removeEntry = (idx: number) => {
    state.timetable.splice(idx, 1);
    save();
    render();
};

(window as any).runAiScan = () => runConflictScan();

// Boot
render();

