// Detect logical conflicts specific to Pharmacy College needs
export const detectConflicts = async (entries: TimetableEntry[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Use gemini-3-pro-preview for advanced logical reasoning tasks
  const prompt = `Analyze this Pharmacy College timetable (KVSR SCOPS) and identify any logical conflicts. 
  Specific considerations for Pharmacy:
  1. Labs usually last 3-4 hours; check for overlaps in long durations.
  2. Pharm.D students have clinical rotations; ensure no room overlaps during clinic hours.
  3. Faculty cannot be in a Lecture and a Lab at the same time.
  4. Same Lab room cannot host two different subjects simultaneously.

  Timetable Data: ${JSON.stringify(entries)}

  Return a structured JSON with a list of conflicts.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          conflicts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, description: 'Room, Faculty, or Time conflict' },
                description: { type: Type.STRING },
                severity: { type: Type.STRING, description: 'High, Medium, or Low' }
              },
              required: ["type", "description"]
            }
          }
        },
        required: ["conflicts"]
      }
    }
  });

  return JSON.parse(response.text || '{"conflicts": []}');
};

// Suggest a suitable faculty replacement with Pharmacy specialization logic
export const suggestSubstitution = async (subject: string, reason: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Use gemini-3-pro-preview for generating academic plans and expert suggestions
  const prompt = `A faculty member teaching "${subject}" at KVSR Siddhartha College of Pharmacy is unavailable due to: ${reason}. 
  Pharmacy specializations include: Pharmaceutics, Pharmacology, Pharmaceutical Analysis, Pharmacognosy, and Pharmacy Practice.

  Please:
  1. Suggest which department profile should provide the substitute.
  2. Suggest a specific profile matching the expertise required for "${subject}".
  3. Provide a brief 1-hour class plan for the substitute.

  Return the response in a clear, professional academic format.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
  });

  return response.text;
};

// Analyze a website URL for college references
export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Use gemini-3-flash-preview for fast web-grounded summarization
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze and summarize this pharmacy related URL: ${url}. Provide context relative to KVSR SCOPS or generic pharmaceutical education.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const summary = response.text || "No summary was generated.";
  const sources: { uri: string; title: string }[] = [];

  // Extract URLs from groundingChunks as required by guidelines
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    for (const chunk of chunks) {
      if (chunk.web) {
        sources.push({
          uri: chunk.web.uri || "",
          title: chunk.web.title || "Reference",
        });
      }
    }
  }

  return { summary, sources };
};

import React, { useState, useEffect } from 'react';
import { getSettings, setSession } from '../../services/dataStore';

const LoginForm: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const settings = getSettings();

  useEffect(() => {
    // Initialize Google Identity Services
    if (settings.googleLoginEnabled && settings.googleClientId && (window as any).google) {
      (window as any).google.accounts.id.initialize({
        client_id: settings.googleClientId,
        callback: handleGoogleResponse,
      });
      (window as any).google.accounts.id.renderButton(
        document.getElementById("googleBtn"),
        { theme: "outline", size: "large", width: "100%" }
      );
    }
  }, [settings.googleLoginEnabled, settings.googleClientId]);

  const handleGoogleResponse = (response: any) => {
    try {
      // In a real app, we would verify this JWT on a server
      // For this demo, we'll decode the payload to check the email
      const payload = JSON.parse(atob(response.credential.split('.')[1]));
      const userEmail = payload.email;

      if (settings.approvedEmails.includes(userEmail)) {
        setSession('google_token_' + Date.now());
        onLogin();
      } else {
        setError(`Access Denied: ${userEmail} is not on the whitelisted emails.`);
      }
    } catch (err) {
      setError('Google Authentication failed.');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === settings.adminUsername && password === settings.adminPassword) {
      setSession('dummy_token_' + Date.now());
      onLogin();
    } else {
      setError('Invalid credentials. Access denied.');
    }
  };

  const isGoogleConfigured = settings.googleLoginEnabled && settings.googleClientId;

  return (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl border-emerald-100 text-center animate-in zoom-in duration-300">
        <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-200 mx-auto mb-6">
          <i className="fa-solid fa-shield-halved text-white text-2xl"></i>
        </div>

        <h2 className="text-2xl font-black text-emerald-900 mb-2">Restricted Access</h2>
        <p className="text-emerald-600 text-sm mb-8 font-medium italic">Please authorize to manage campus data</p>

        <form onSubmit={handleLogin} className="space-y-4 text-left">
          {error && <p className="text-xs text-red-500 font-bold bg-red-50 p-3 rounded-lg border border-red-100 mb-4">{error}</p>}

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Username</label>
            <input 
              type="text" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500 transition-all" 
              value={username}
              onChange={e => setUsername(e.target.value)}
              required
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Password</label>
            <input 
              type="password" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500 transition-all" 
              value={password}
              onChange={e => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit"
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-bold transition-all shadow-lg shadow-emerald-200 mt-4 active:scale-95"
          >
            Authenticate
          </button>
        </form>

        {isGoogleConfigured && (
          <div className="mt-8 pt-8 border-t border-emerald-100">
            <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest mb-4">Or sign in with SSO</p>
            <div id="googleBtn" className="w-full overflow-hidden rounded-xl"></div>
          </div>
        )}

        <p className="mt-8 text-[10px] text-emerald-300 font-bold uppercase tracking-tight">
          Session Encryption Active • Siddartha IT Dept
        </p>
      </div>
    </div>
  );
};

