import { TimetableEntry, AnalysisResult, AppState } from "../types";
import { getState } from "./dataStore";

// Local Conflict Detection (No AI required)
export const detectConflicts = (entries: TimetableEntry[]) => {
  const conflicts: { type: string; description: string; severity: string }[] = [];

  // 1. Check for Faculty Overlaps (Same teacher in two places at once)
  const facultyMap = new Map<string, string>(); // key: day-slot-facultyId, val: entryId

  entries.forEach(e => {
    const key = `${e.day}-${e.slotId}-${e.facultyId}`;
    if (facultyMap.has(key)) {
      conflicts.push({
        type: "Faculty Conflict",
        description: `Faculty is assigned to multiple classes at the same time on ${e.day}.`,
        severity: "High"
      });
    }
    facultyMap.set(key, e.id);
  });

  // 2. Check for Room/Class Overlaps
  const classMap = new Map<string, string>(); // key: day-slot-classId
  entries.forEach(e => {
    const key = `${e.day}-${e.slotId}-${e.classId}`;
    if (classMap.has(key)) {
      conflicts.push({
        type: "Class Overlap",
        description: `Multiple sessions assigned to the same class group at once on ${e.day}.`,
        severity: "Medium"
      });
    }
    classMap.set(key, e.id);
  });

  return { conflicts };
};

// Local Substitution Logic
export const suggestSubstitution = async (subjectName: string, reason: string) => {
  const state = getState();
  const subject = state.subjects.find(s => s.name === subjectName);

  // Find faculty in same department
  const substitutes = state.staff.filter(s => 
    s.isActive && 
    (subject ? s.department === subject.department : true)
  );

  const sub = substitutes[0] || state.staff[0];

  return `Local Recommendation System:

  Suggested Substitute: ${sub ? sub.name : "System Default"}
  Reason: Matching expertise in ${sub ? sub.department : "General Pharmacy"}.

  Class Plan:
  - Subject Overview: ${subjectName}
  - Activity: Discussion on ${reason.toLowerCase().includes('medical') ? 'recent therapeutic trends' : 'core pharmaceutical concepts'}.
  - Assignment: Review the previous lab session results.`;
};

