import { TimetableEntry, AnalysisResult, AppState, StaffMember } from "../types";
import { getState } from "./dataStore";

/**
 * Local Conflict Detection Logic
 * Analyzes the timetable for faculty and class schedule overlaps.
 */
export const detectConflicts = (entries: TimetableEntry[]) => {
  const conflicts: { type: string; description: string; severity: string }[] = [];

  // Faculty schedule map: day-slot-facultyId
  const facultyMap = new Map<string, TimetableEntry>();
  // Class schedule map: day-slot-classId
  const classMap = new Map<string, TimetableEntry>();

  const state = getState();

  entries.forEach(e => {
    const facultyKey = `${e.day}-${e.slotId}-${e.facultyId}`;
    const classKey = `${e.day}-${e.slotId}-${e.classId}`;

    // Check Faculty Double-booking
    if (facultyMap.has(facultyKey)) {
      const existing = facultyMap.get(facultyKey)!;
      const faculty = state.staff.find(s => s.id === e.facultyId);
      const className1 = state.classes.find(c => c.id === existing.classId)?.name;
      const className2 = state.classes.find(c => c.id === e.classId)?.name;

      conflicts.push({
        type: "Faculty Conflict",
        description: `${faculty?.name || 'Faculty'} is assigned to both ${className1} and ${className2} during the same period on ${e.day}.`,
        severity: "High"
      });
    }
    facultyMap.set(facultyKey, e);

    // Check Class Overlap (though UI prevents it, logic should be robust)
    if (classMap.has(classKey)) {
      const existing = classMap.get(classKey)!;
      if (existing.id !== e.id) {
        const className = state.classes.find(c => c.id === e.classId)?.name;
        conflicts.push({
          type: "Class Overlap",
          description: `${className} has multiple subjects assigned to the same time slot on ${e.day}.`,
          severity: "Medium"
        });
      }
    }
    classMap.set(classKey, e);
  });

  return { conflicts };
};

