export const suggestSubstitution = async (subjectName: string, reason: string) => {
  const state = getState();
  const subject = state.subjects.find(s => s.name === subjectName);

  // 1. Find faculty in same department
  const sameDeptStaff = state.staff.filter(s => 
    s.isActive && 
    (subject ? s.department === subject.department : true)
  );

  // 2. Pick a candidate
  const candidate = sameDeptStaff.length > 0 ? sameDeptStaff[0] : state.staff.find(s => s.isActive);

  // Simulate network delay for "processing" feel
  await new Promise(r => setTimeout(r, 600));

  if (!candidate) return "No active faculty available for substitution.";

  return `System-Generated Recommendation:

  Recommended Substitute: ${candidate.name}
  Department: ${candidate.department}
  Match Reason: Expertise in ${candidate.specialization.join(', ') || candidate.department}.

  Academic Instruction for ${subjectName}:
  1. Review the current curriculum status for the session.
  2. Handle administrative attendance.
  3. Contextualize the lesson with respect to ${reason.toLowerCase().includes('conference') ? 'recent pharmaceutical summits' : 'clinical practice standards'}.
  4. Suggested Activity: Interactive Q&A on core terminology.`;
};

/**
 * Local Website Analysis Logic (Deterministic Mock)
 */
export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  await new Promise(r => setTimeout(r, 1200));

  const isSiddartha = url.toLowerCase().includes('siddartha') || url.toLowerCase().includes('bolt.host');

  return {
    summary: isSiddartha 
      ? `The URL ${url} is identified as the official KVSR SCOPS Smart Portal. This secure digital infrastructure provides automated timetable management, real-time faculty coordination, and academic workload analysis. Key features include centralized schedule grids and an AI-simulated substitution engine designed specifically for the Pharmacy curriculum.`
      : `General Analysis for ${url}: This resource relates to pharmaceutical education and academic management. The system identifies it as a supporting asset for institutional research and student data coordination. No security threats detected.`,
    sources: [
      { uri: "https://siddartha.edu", title: "KVSR SCOPS Main Site" },
      { uri: url, title: "Requested Resource Link" }
    ]
  };
};

