                        onChange={e => setSelectedTargetId(e.target.value)}
                        className="bg-transparent text-[10px] font-black uppercase border-none focus:ring-0 ml-2"
                      >
                        {gridMode === 'class' 
                          ? state.classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.section})</option>)
                          : state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)
                        }
                      </select>
                    </div>
                 </div>

                 {/* Interactive Grid */}
                 <div className="bg-white rounded-[2rem] border border-emerald-100 overflow-hidden shadow-sm relative">
                    <div className="overflow-x-auto custom-scrollbar">
                      <table className="w-full border-collapse">
                        <thead>
                          <tr className="bg-emerald-50/50">
                            <th className="p-4 border-b border-emerald-100"></th>
                            {state.config.workingDays.map(day => (
                              <th key={day} className="p-4 text-[10px] font-black text-emerald-800 uppercase tracking-widest border-b border-l border-emerald-100 min-w-[150px]">{day}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {state.config.timeSlots.map(slot => (
                            <tr key={slot.id}>
                              <td className="p-4 border-b border-emerald-100 bg-emerald-50/30">
                                <p className="text-[10px] font-black text-emerald-900 whitespace-nowrap">{slot.label}</p>
                                <p className="text-[8px] font-bold text-slate-400">{slot.start} - {slot.end}</p>
                              </td>
                              {state.config.workingDays.map(day => {
                                const entry = getEntry(day, slot.id);
                                if (slot.isBreak) return <td key={day} className="p-4 bg-amber-50/30 border-b border-l border-emerald-100 text-center"><i className="fa-solid fa-mug-hot text-amber-200"></i></td>;

                                return (
                                  <td 
                                    key={day} 
                                    onClick={() => setEditingSlot({day, slotId: slot.id})}
                                    className="p-3 border-b border-l border-emerald-100 grid-cell cursor-pointer relative"
                                  >
                                    {entry ? (
                                      <div className="bg-emerald-600 p-3 rounded-xl text-white shadow-sm">
                                        <p className="text-[10px] font-black uppercase mb-1 leading-none">{state.subjects.find(s => s.id === entry.subjectId)?.name}</p>
                                        <p className="text-[8px] font-bold opacity-80 uppercase leading-none">
                                          {gridMode === 'class' 
                                            ? state.staff.find(st => st.id === entry.facultyId)?.name 
                                            : state.classes.find(cl => cl.id === entry.classId)?.name
                                          }
                                        </p>
                                      </div>
                                    ) : (
                                      <div className="flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                                        <i className="fa-solid fa-plus text-emerald-200"></i>
                                      </div>
                                    )}

                                    {/* Assignment Modal/Popover */}
                                    {editingSlot?.day === day && editingSlot?.slotId === slot.id && (
                                      <div className="absolute inset-0 z-50 bg-white p-2 rounded-xl shadow-2xl border border-emerald-200 flex flex-col gap-2 min-w-[200px]" onClick={e => e.stopPropagation()}>
                                         <div className="flex justify-between items-center px-1">
                                            <span className="text-[8px] font-black text-emerald-600 uppercase">Assignment</span>
                                            <button onClick={() => setEditingSlot(null)} className="text-slate-300 hover:text-red-500"><i className="fa-solid fa-xmark text-[10px]"></i></button>
                                         </div>
                                         <select 
                                          className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2"
                                          defaultValue={entry?.subjectId || ""}
                                          onChange={e => {
                                            const subId = e.target.value;
                                            if (gridMode === 'class') {
                                               // Staff needed
                                               const facultyId = (document.getElementById(`facultySelect-${day}-${slot.id}`) as HTMLSelectElement)?.value;
                                               handleAssign(day, slot.id, subId, facultyId, selectedTargetId);
                                            } else {
                                               // Class needed
                                               const classId = (document.getElementById(`classSelect-${day}-${slot.id}`) as HTMLSelectElement)?.value;
                                               handleAssign(day, slot.id, subId, selectedTargetId, classId);
                                            }
                                          }}
                                         >
                                            <option value="">- Clear Slot -</option>
                                            {state.subjects.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                         </select>
                                         {gridMode === 'class' ? (
                                           <select id={`facultySelect-${day}-${slot.id}`} className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2" defaultValue={entry?.facultyId || ""}>
                                              {state.staff.map(st => <option key={st.id} value={st.id}>{st.name}</option>)}
                                           </select>
                                         ) : (
                                           <select id={`classSelect-${day}-${slot.id}`} className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2" defaultValue={entry?.classId || ""}>
                                              {state.classes.map(cl => <option key={cl.id} value={cl.id}>{cl.name} ({cl.section})</option>)}
                                           </select>
                                         )}
                                      </div>
                                    )}
                                  </td>
                                );
                              })}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                 </div>

                 <div className="p-8 bg-amber-50 rounded-[2.5rem] border border-amber-100 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                       <div className="w-12 h-12 bg-amber-100 rounded-2xl flex items-center justify-center text-amber-600 text-xl"><i className="fa-solid fa-wand-magic-sparkles"></i></div>
                       <div>
                          <p className="font-black text-emerald-900 text-sm">Smart Recommendation</p>
                          <p className="text-[10px] font-medium text-amber-700">The system analyzes current entries to suggest optimized scheduling blocks.</p>
                       </div>
                    </div>
                    <button className="px-6 py-3 bg-white border border-amber-200 text-amber-600 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-amber-100 transition-all">Optimize Grid</button>
                 </div>
              </div>
            )}

            {/* 6. SUBSTITUTION */}
            {activeTab === 'sub' && (
              <div className="space-y-10 animate-in fade-in">
                 <h3 className="text-2xl font-black text-emerald-900">Faculty Substitution Engine</h3>

                 <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                    <div className="lg:col-span-1 p-8 bg-emerald-50 rounded-[2.5rem] border border-emerald-100 space-y-6">
                       <h4 className="text-xs font-black text-emerald-900 uppercase tracking-widest mb-4">New Request</h4>
                       <div className="space-y-4">
                          <div>
                             <Label>Original Faculty</Label>
                             <select id="sub_orig" className="w-full p-4 rounded-2xl bg-white border-none text-xs font-bold">
                                {state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                             </select>
                          </div>
                          <div>
                             <Label>Reason for Absence</Label>
                             <input id="sub_reason" type="text" className="w-full p-4 rounded-2xl bg-white border-none text-xs font-medium" placeholder="Conference / Medical..." />
                          </div>
                          <button 
                            onClick={async () => {
                              const fId = (document.getElementById('sub_orig') as HTMLSelectElement).value;
                              const reason = (document.getElementById('sub_reason') as HTMLInputElement).value;
                              const faculty = state.staff.find(s => s.id === fId);
                              if (!faculty) return;
                              setIsAiLoading(true);
                              // Calls local deterministic suggestion
                              const suggestion = await suggestSubstitution('Pharmaceutics-I', reason);
                              addLog(`Substitution suggestion generated for ${faculty.name}`);
                              alert(`SYSTEM RECOMMENDATION:\n${suggestion}`);
                              setIsAiLoading(false);
                            }}
                            className="w-full py-4 bg-emerald-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all active:scale-95"
                          >
                             {isAiLoading ? <i className="fa-solid fa-dna fa-spin mr-2"></i> : 'Generate Recommendation'}
                          </button>
                       </div>
                    </div>

                    <div className="lg:col-span-2 space-y-4">
                       <Label>Recent Substitution Requests</Label>
                       <div className="space-y-4">
                          {state.substitutions.length === 0 ? <p className="text-slate-300 italic text-center py-20 text-xs">No pending substitution requests.</p> : 
                            state.substitutions.map(sub => (
                              <div key={sub.id} className="p-6 bg-white border border-slate-50 rounded-3xl shadow-sm flex items-center justify-between">
                                 <div>
                                    <p className="text-[10px] font-black text-emerald-600 uppercase mb-1">Date: {sub.date}</p>
                                    <p className="font-bold text-emerald-900 text-sm">Substitute Needed</p>
                                    <p className="text-[10px] text-slate-400 font-medium">Reason: {sub.reason}</p>
                                 </div>
                                 <div className="flex gap-2">
                                    <button className="px-4 py-2 bg-emerald-500 text-white rounded-xl text-[9px] font-black uppercase shadow-md shadow-emerald-500/20 transition-all active:scale-95">Approve</button>
                                    <button className="px-4 py-2 bg-slate-100 text-slate-400 rounded-xl text-[9px] font-black uppercase transition-all active:scale-95">Cancel</button>
                                 </div>
                              </div>
                            ))
                          }
                       </div>
                    </div>
                 </div>
              </div>
            )}

            {/* 7. SECURITY */}
            {activeTab === 'sec' && (
              <div className="space-y-10 animate-in zoom-in-95 max-w-2xl">
                 <h3 className="text-2xl font-black text-emerald-900">Security Gatekeeper</h3>

                 <div className="space-y-8">
                    <div className="p-8 bg-white border border-slate-50 rounded-[2.5rem] shadow-sm space-y-6">
                       <h4 className="text-xs font-black text-emerald-900 uppercase tracking-widest mb-4">Primary Credentials</h4>
                       <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-1">
                             <Label>Username</Label>
                             <input type="text" value={state.settings.adminUsername} className="w-full p-3 rounded-xl bg-slate-50 border-none text-sm font-bold focus:ring-2 focus:ring-emerald-500 transition-all" onChange={e => setState({...state, settings: {...state.settings, adminUsername: e.target.value}})} />
                          </div>
                          <div className="space-y-1">
                             <Label>Password</Label>
                             <input type="password" value={state.settings.adminPassword} className="w-full p-3 rounded-xl bg-slate-50 border-none text-sm font-bold focus:ring-2 focus:ring-emerald-500 transition-all" onChange={e => setState({...state, settings: {...state.settings, adminPassword: e.target.value}})} />
                          </div>
                       </div>
                       <button onClick={() => addLog('Security credentials updated')} className="text-[10px] font-black text-emerald-600 uppercase underline">Update Profile</button>
                    </div>

                    <div className="p-8 bg-slate-900 rounded-[2.5rem] shadow-xl space-y-6 text-white relative overflow-hidden">
                       <div className="flex items-center justify-between relative z-10">
                          <h4 className="text-xs font-black uppercase tracking-widest text-emerald-400">Google OAuth 2.0 (SSO)</h4>
                          <button 
                            onClick={() => {
                               setState({...state, settings: {...state.settings, googleLoginEnabled: !state.settings.googleLoginEnabled}});
                               addLog(`Google OAuth toggled: ${!state.settings.googleLoginEnabled ? 'ENABLED' : 'DISABLED'}`);
                            }}
                            className={`w-12 h-6 rounded-full relative transition-all ${state.settings.googleLoginEnabled ? 'bg-emerald-500' : 'bg-slate-700'}`}
                          >
                             <div className={`absolute top-1 w-4 h-4 bg-white rounded-full shadow-sm transition-all ${state.settings.googleLoginEnabled ? 'left-7' : 'left-1'}`}></div>
                          </button>
                       </div>

                       {state.settings.googleLoginEnabled && (
                         <div className="space-y-6 animate-in slide-in-from-top-4 duration-500 relative z-10">
                            <div className="space-y-1">
                               <p className="text-[8px] font-black text-emerald-500 uppercase ml-1">Google Client ID</p>
                               <input type="text" value={state.settings.googleClientId} className="w-full p-3 rounded-xl bg-white/10 border-none text-[10px] font-mono" placeholder="xxx-yyy.apps.googleusercontent.com" onChange={e => setState({...state, settings: {...state.settings, googleClientId: e.target.value}})} />
                            </div>
                            <div className="space-y-1">
                               <p className="text-[8px] font-black text-emerald-500 uppercase ml-1">Google Client Secret</p>
                               <input type="password" value={state.settings.googleClientSecret} className="w-full p-3 rounded-xl bg-white/10 border-none text-[10px] font-mono" placeholder="••••••••" onChange={e => setState({...state, settings: {...state.settings, googleClientSecret: e.target.value}})} />
                            </div>
                            <div className="space-y-1">
                               <p className="text-[8px] font-black text-emerald-500 uppercase ml-1">Allowed Email Whitelist (Comma separated)</p>
                               <textarea value={state.settings.approvedEmails.join(', ')} className="w-full p-4 rounded-xl bg-white/10 border-none h-24 text-[10px] font-medium custom-scrollbar" placeholder="admin@siddartha.edu, dean@siddartha.edu" onChange={e => setState({...state, settings: {...state.settings, approvedEmails: e.target.value.split(',').map(em => em.trim()).filter(Boolean)}})} />
                            </div>
                         </div>
                       )}
                       <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>
                    </div>
                 </div>
              </div>
            )}

            {/* 8. SYSTEM */}
            {activeTab === 'sys' && (
              <div className="space-y-10 animate-in fade-in">
                 <h3 className="text-2xl font-black text-emerald-900">System Controls</h3>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="p-10 glass border-emerald-100 rounded-[3rem] text-center transition-all hover:shadow-emerald-900/10">
                       <i className="fa-solid fa-cloud-arrow-down text-4xl text-emerald-200 mb-6"></i>
                       <h4 className="text-lg font-black text-emerald-900 mb-2">Data Integrity Backup</h4>
                       <p className="text-xs text-slate-400 mb-8 max-w-xs mx-auto">Export the entire campus state as a JSON bundle for cold-storage backup.</p>
                       <button onClick={handleBackup} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-emerald-600/20 transition-all active:scale-95 hover:bg-emerald-700">Download Snapshot</button>
                    </div>

                    <div className="p-10 glass border-red-100 rounded-[3rem] text-center transition-all hover:shadow-red-900/10">
                       <i className="fa-solid fa-trash-can-arrow-up text-4xl text-red-100 mb-6"></i>
                       <h4 className="text-lg font-black text-red-900 mb-2">System Purge</h4>
                       <p className="text-xs text-slate-400 mb-8 max-w-xs mx-auto">WARNING: This will wipe all timetables, staff and academic data permanently.</p>
                       <button 
                         onClick={() => {
                            if(confirm("DANGER: WIPE ENTIRE DATABASE?")) {
                               localStorage.clear();
                               window.location.reload();
                            }
                         }}
                         className="w-full py-4 bg-red-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-red-500/20 transition-all active:scale-95 hover:bg-red-600"
                       >
                         Wipe Database
                       </button>
                    </div>
                 </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

