export const getState = (): AppState => {
  const data = localStorage.getItem(KEYS.STATE);
  if (!data) return INITIAL_STATE;
  try {
    const parsed = JSON.parse(data);
    // Ensure attendance array exists for legacy data
    if (!parsed.attendance) parsed.attendance = [];
    return parsed;
  } catch (e) {
    return INITIAL_STATE;
  }
};

export const saveState = (state: AppState) => {
  localStorage.setItem(KEYS.STATE, JSON.stringify(state));
};

export const setSession = (token: string | null) => {
  if (token) localStorage.setItem(KEYS.AUTH, token);
  else localStorage.removeItem(KEYS.AUTH);
};

export const getSession = () => localStorage.getItem(KEYS.AUTH);
export const getSettings = () => getState().settings;
export const getTimetable = () => getState().timetable;

import React, { useState, useEffect } from 'react';
import { getState, saveState } from '../../services/dataStore';
import { AppState, TimeSlot, StaffMember, Substitution, Subject, ClassRoom, TimetableEntry, SystemLog, AttendanceRecord } from '../../types';
import { suggestSubstitution, detectConflicts } from '../../services/geminiService';

const Label: React.FC<React.PropsWithChildren<{}>> = ({ children }) => (
  <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest block mb-1.5 ml-1">{children}</label>
);

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [state, setState] = useState<AppState>(getState());
  const [activeTab, setActiveTab] = useState<'dash' | 'inst' | 'acad' | 'staff' | 'time' | 'sub' | 'attn' | 'sec' | 'sys'>('dash');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [conflicts, setConflicts] = useState<{ type: string; description: string; severity: string }[]>([]);

  // Faculty Edit State
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);

  // Timetable Grid states
  const [gridMode, setGridMode] = useState<'class' | 'staff'>('class');
  const [selectedTargetId, setSelectedTargetId] = useState('');
  const [editingSlot, setEditingSlot] = useState<{day: string, slotId: string} | null>(null);

  useEffect(() => {
    saveState(state);
    const { conflicts: newConflicts } = detectConflicts(state.timetable);
    setConflicts(newConflicts);
  }, [state]);

  useEffect(() => {
    if (gridMode === 'class' && state.classes.length > 0 && !selectedTargetId) {
      setSelectedTargetId(state.classes[0].id);
    } else if (gridMode === 'staff' && state.staff.length > 0 && !selectedTargetId) {
      setSelectedTargetId(state.staff[0].id);
    }
  }, [gridMode, state.classes, state.staff]);

  const addLog = (action: string) => {
    const newLog: SystemLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      user: state.settings.adminUsername,
      action
    };
    setState(prev => ({ ...prev, logs: [newLog, ...prev.logs].slice(0, 50) }));
  };

  const handleBackup = () => {
    const dataStr = JSON.stringify(state);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `scops_backup_${new Date().toISOString()}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
    addLog('System data backup exported');
  };

  // Timetable logic
  const getEntry = (day: string, slotId: string) => {
    return state.timetable.find(e => 
      e.day === day && 
      e.slotId === slotId && 
      (gridMode === 'class' ? e.classId === selectedTargetId : e.facultyId === selectedTargetId)
    );
  };

  const handleAssign = (day: string, slotId: string, subjectId: string, facultyId: string, classId: string) => {
    const newTimetable = state.timetable.filter(e => 
      !(e.day === day && e.slotId === slotId && (gridMode === 'class' ? e.classId === classId : e.facultyId === facultyId))
    );

    if (subjectId) {
      newTimetable.push({
        id: 'te-' + Date.now(),
        day,
        slotId,
        subjectId,
        facultyId,
        classId,
        type: 'Lecture'
      });
      addLog(`Assigned ${state.subjects.find(s => s.id === subjectId)?.name} to ${day} ${state.config.timeSlots.find(s => s.id === slotId)?.label}`);
    } else {
      addLog(`Cleared slot ${day} ${state.config.timeSlots.find(s => s.id === slotId)?.label}`);
    }

    setState({...state, timetable: newTimetable});
    setEditingSlot(null);
  };

  const handleMarkAttendance = (staffId: string) => {
    const today = new Date().toISOString().split('T')[0];
    const alreadyMarked = state.attendance.some(a => a.staffId === staffId && a.date === today);

    if (alreadyMarked) {
      alert("Attendance already marked for today.");
      return;
    }

    const newRecord: AttendanceRecord = {
      id: Date.now().toString(),
      staffId,
      date: today,
      timestamp: new Date().toLocaleTimeString(),
      status: 'Present'
    };

    setState(prev => ({ ...prev, attendance: [...prev.attendance, newRecord] }));
    addLog(`Attendance marked for ${state.staff.find(s => s.id === staffId)?.name}`);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* Sidebar */}
        <aside className="lg:w-72 space-y-2">
          <div className="p-8 mb-6 glass rounded-[2.5rem] border-emerald-100 shadow-xl shadow-emerald-900/5">
             <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white text-xl mb-4 shadow-lg shadow-emerald-600/30">
                <i className="fa-solid fa-user-shield"></i>
             </div>
             <h2 className="text-xl font-black text-emerald-900 leading-none">ADMIN CORE</h2>
             <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mt-1">v5.2 Platinum Edition</p>
          </div>

          <nav className="space-y-1">
            {[
              { id: 'dash', icon: 'fa-chart-pie', label: 'Monitor' },
              { id: 'inst', icon: 'fa-university', label: 'Institution' },
              { id: 'acad', icon: 'fa-book-open', label: 'Academic' },
              { id: 'staff', icon: 'fa-users-gear', label: 'Faculty' },
              { id: 'attn', icon: 'fa-clipboard-user', label: 'Attendance' },
              { id: 'time', icon: 'fa-calendar-check', label: 'Timetables' },
              { id: 'sub', icon: 'fa-user-clock', label: 'Substitutions' },
              { id: 'sec', icon: 'fa-shield-halved', label: 'Security' },
              { id: 'sys', icon: 'fa-sliders', label: 'System' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold transition-all ${
                  activeTab === tab.id ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-900/10' : 'text-emerald-800 hover:bg-emerald-50'
                }`}
              >
                <i className={`fa-solid ${tab.icon} w-5`}></i>
                <span className="text-[10px] uppercase tracking-widest">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button onClick={onLogout} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-10 transition-all">
            <i className="fa-solid fa-power-off w-5"></i>
            <span className="text-[10px] uppercase tracking-widest">Force Logout</span>
          </button>
        </aside>

        {/* Content Area */}
        <div className="flex-grow">
          <div className="glass rounded-[3rem] p-10 min-h-[800px] border-emerald-100 shadow-2xl relative overflow-hidden">

            {/* 1. MONITOR */}
            {activeTab === 'dash' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <h3 className="text-2xl font-black text-emerald-900">System Monitoring</h3>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                  {[
                    { label: 'Active Staff', val: state.staff.filter(s => s.isActive).length, icon: 'fa-user-tie', color: 'text-blue-600' },
                    { label: 'Substitutions', val: state.substitutions.filter(s => s.status === 'Approved').length, icon: 'fa-clock', color: 'text-amber-600' },
                    { label: 'Academic Load', val: state.timetable.length, icon: 'fa-book', color: 'text-emerald-600' },
                    { label: 'System Health', val: conflicts.length > 0 ? 'Warning' : '99.9%', icon: 'fa-heart-pulse', color: conflicts.length > 0 ? 'text-amber-500' : 'text-red-500' }
                  ].map((stat, i) => (
                    <div key={i} className="p-6 bg-white border border-slate-50 rounded-3xl shadow-sm">
                      <i className={`fa-solid ${stat.icon} ${stat.color} mb-3 text-lg opacity-40`}></i>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
                      <p className="text-2xl font-black text-emerald-900">{stat.val}</p>
                    </div>
                  ))}
                </div>

                {conflicts.length > 0 && (
                  <div className="p-8 bg-amber-50 rounded-[2.5rem] border border-amber-100 animate-in slide-in-from-top-4">
                     <div className="flex items-center gap-4 mb-4">
                        <i className="fa-solid fa-triangle-exclamation text-amber-500 text-xl"></i>
                        <h4 className="font-black text-amber-900 uppercase text-xs tracking-widest">Schedule Conflicts Detected</h4>
                     </div>
                     <div className="space-y-3">
                        {conflicts.map((c, i) => (
                          <div key={i} className="flex items-start gap-4 p-4 bg-white rounded-2xl border border-amber-100 text-xs">
                             <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase ${c.severity === 'High' ? 'bg-red-100 text-red-600' : 'bg-amber-100 text-amber-600'}`}>{c.severity}</span>
                             <div>
                                <p className="font-bold text-emerald-900">{c.type}</p>
                                <p className="text-slate-500 mt-1">{c.description}</p>
                             </div>
                          </div>
                        ))}
                     </div>
                  </div>
                )}

                <div className="p-8 bg-emerald-950 rounded-[2.5rem] text-white overflow-hidden relative">
                   <h4 className="font-black text-lg mb-6">Activity Audit Trail</h4>
                   <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-4">
                      {state.logs.length === 0 ? <p className="text-emerald-700 italic text-xs">No recent activity detected.</p> :
                       state.logs.map(log => (
                         <div key={log.id} className="flex items-center gap-4 text-xs font-mono py-2 border-b border-white/5 last:border-0">
                            <span className="text-emerald-500">[{log.timestamp}]</span>
                            <span className="text-emerald-100/50 uppercase font-black tracking-widest text-[9px]">{log.user}</span>
                            <span className="text-emerald-100">{log.action}</span>
                         </div>
                       ))
                      }
                   </div>
                   <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-emerald-500 opacity-10 blur-3xl"></div>
                </div>
              </div>
            )}

            {/* 4. FACULTY */}
            {activeTab === 'staff' && (
              <div className="space-y-10 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-2xl font-black text-emerald-900">Faculty Directory</h3>
                    <button onClick={() => {
                       const newStaff: StaffMember = { id: 's' + Date.now(), name: 'New Faculty', email: '', department: 'Pharmaceutics', specialization: [], assignedSubjects: [], isActive: true, availability: ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'] };
                       setState({...state, staff: [...state.staff, newStaff]});
                    }} className="px-8 py-3 bg-emerald-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-emerald-200">Add Faculty Member</button>
                 </div>

                 {editingStaff && (
                   <div className="p-8 bg-emerald-50 rounded-[2rem] border border-emerald-100 animate-in slide-in-from-top-4">
                      <h4 className="text-xs font-black text-emerald-900 uppercase tracking-widest mb-6">Edit Faculty Member</h4>
                      <div className="grid grid-cols-2 gap-6">
                         <div>
                            <Label>Full Name</Label>
                            <input type="text" value={editingStaff.name} onChange={e => setEditingStaff({...editingStaff, name: e.target.value})} className="w-full p-3 rounded-xl bg-white border border-emerald-100 text-sm font-bold" />
                         </div>
                         <div>
                            <Label>Department</Label>
                            <select value={editingStaff.department} onChange={e => setEditingStaff({...editingStaff, department: e.target.value})} className="w-full p-3 rounded-xl bg-white border border-emerald-100 text-sm font-bold">
                               <option>Pharmaceutics</option>
                               <option>Pharmacology</option>
                               <option>Pharmaceutical Chemistry</option>
                               <option>Pharmacognosy</option>
                            </select>
                         </div>
                      </div>
                      <div className="flex gap-2 mt-8">
                         <button onClick={() => {
                            const newStaff = state.staff.map(s => s.id === editingStaff.id ? editingStaff : s);
                            setState({...state, staff: newStaff});
                            setEditingStaff(null);
                            addLog(`Updated faculty: ${editingStaff.name}`);
                         }} className="px-6 py-2.5 bg-emerald-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest">Save Changes</button>
                         <button onClick={() => setEditingStaff(null)} className="px-6 py-2.5 bg-white border border-slate-200 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest">Cancel</button>
                      </div>
                   </div>
                 )}

                 <div className="bg-white border border-slate-100 rounded-[2.5rem] overflow-hidden shadow-sm">
                    <table className="w-full text-left">
                       <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                          <tr>
                             <th className="px-8 py-6">Name</th>
                             <th className="px-8 py-6 text-center">Department</th>
                             <th className="px-8 py-6 text-center">Actions</th>
                          </tr>
                       </thead>
                       <tbody className="divide-y divide-slate-50">
                          {state.staff.map(s => (
                             <tr key={s.id} className="group hover:bg-slate-50/50 transition-all">
                                <td className="px-8 py-6">
                                   <p className="font-bold text-emerald-900">{s.name}</p>
                                   <p className="text-[10px] text-slate-400 font-medium">{s.email || 'No email set'}</p>
                                </td>
                                <td className="px-8 py-6 text-center">
                                   <span className="px-3 py-1 bg-emerald-50 rounded-lg text-[9px] font-black text-emerald-700 uppercase tracking-widest">{s.department}</span>
                                </td>
                                <td className="px-8 py-6 text-center">
                                   <div className="flex items-center justify-center gap-3">
                                      <button 
                                        onClick={() => setEditingStaff(s)}
                                        className="w-8 h-8 rounded-lg bg-emerald-50 text-emerald-600 flex items-center justify-center hover:bg-emerald-600 hover:text-white transition-all shadow-sm"
                                      >
                                         <i className="fa-solid fa-pen-to-square text-xs"></i>
                                      </button>
                                      <button 
                                        onClick={() => {
                                          if(confirm(`Delete faculty member ${s.name}?`)) {
                                            setState({...state, staff: state.staff.filter(st => st.id !== s.id)});
                                            addLog(`Deleted faculty: ${s.name}`);
                                          }
                                        }}
                                        className="w-8 h-8 rounded-lg bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-600 hover:text-white transition-all shadow-sm"
                                      >
                                         <i className="fa-solid fa-circle-minus text-xs"></i>
                                      </button>
                                   </div>
                                </td>
                             </tr>
                          ))}
                       </tbody>
                    </table>
                 </div>
              </div>
            )}

            {/* ATTENDANCE PANEL */}
            {activeTab === 'attn' && (
              <div className="space-y-10 animate-in fade-in">
                 <h3 className="text-2xl font-black text-emerald-900">Faculty Daily Attendance</h3>

                 <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                    <div className="lg:col-span-1 p-8 bg-emerald-50 rounded-[2.5rem] border border-emerald-100 space-y-6">
                       <h4 className="text-xs font-black text-emerald-900 uppercase tracking-widest mb-4">Mark Your Attendance</h4>
                       <div className="space-y-4">
                          <div>
                             <Label>Select Faculty Member</Label>
                             <select id="attn_staff" className="w-full p-4 rounded-2xl bg-white border-none text-xs font-bold shadow-inner">
                                {state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                             </select>
                          </div>
                          <button 
                            onClick={() => {
                              const fId = (document.getElementById('attn_staff') as HTMLSelectElement).value;
                              handleMarkAttendance(fId);
                            }}
                            className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-emerald-200 transition-all active:scale-95"
                          >
                             Submit Attendance
                          </button>
                          <p className="text-[9px] text-emerald-500 italic text-center">Note: Self-attendance is logged with timestamp for verification.</p>
                       </div>
                    </div>

                    <div className="lg:col-span-2 space-y-4">
                       <Label>Today's Log: {new Date().toDateString()}</Label>
                       <div className="space-y-4 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
                          {state.attendance.filter(a => a.date === new Date().toISOString().split('T')[0]).length === 0 ? (
                            <div className="p-20 text-center glass rounded-[2rem] border-dashed border-emerald-100">
                               <i className="fa-solid fa-clipboard-check text-slate-100 text-4xl mb-4"></i>
                               <p className="text-slate-300 italic text-xs">No attendance records submitted yet for today.</p>
                            </div>
                          ) : (
                            state.attendance.filter(a => a.date === new Date().toISOString().split('T')[0]).map(record => {
                              const faculty = state.staff.find(s => s.id === record.staffId);
                              return (
                                <div key={record.id} className="p-6 bg-white border border-slate-50 rounded-3xl shadow-sm flex items-center justify-between">
                                   <div className="flex items-center gap-4">
                                      <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                                         <i className="fa-solid fa-user-check"></i>
                                      </div>
                                      <div>
                                         <p className="font-bold text-emerald-900 text-sm">{faculty?.name || 'Unknown'}</p>
                                         <p className="text-[10px] text-slate-400 font-medium">Logged at {record.timestamp}</p>
                                      </div>
                                   </div>
                                   <span className="px-4 py-2 bg-emerald-100 text-emerald-700 rounded-xl text-[9px] font-black uppercase tracking-widest">Present</span>
                                </div>
                              );
                            })
                          )}
                       </div>
                    </div>
                 </div>
              </div>
            )}

            {/* 5. TIMETABLE MANAGEMENT (GRID) */}
            {activeTab === 'time' && (
              <div className="space-y-8 animate-in fade-in">
                 <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                    <div>
                      <h3 className="text-2xl font-black text-emerald-900">Schedule Grid Editor</h3>
                      <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Real-time Visual Management</p>
                    </div>

                    <div className="flex items-center gap-4 bg-slate-100 p-1.5 rounded-2xl">
                      <button 
                        onClick={() => { setGridMode('class'); setSelectedTargetId(state.classes[0]?.id || ''); }}
                        className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${gridMode === 'class' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-400'}`}
                      >Class</button>
                      <button 
                        onClick={() => { setGridMode('staff'); setSelectedTargetId(state.staff[0]?.id || ''); }}
                        className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${gridMode === 'staff' ? 'bg-white text-emerald-700 shadow-sm' : 'text-slate-400'}`}
                      >Faculty</button>
                      <select 
                        value={selectedTargetId} 
                        onChange={e => setSelectedTargetId(e.target.value)}
                        className="bg-transparent text-[10px] font-black uppercase border-none focus:ring-0 ml-2"
                      >
                        {gridMode === 'class' 
                          ? state.classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.section})</option>)
                          : state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)
                        }
                      </select>
                    </div>
                 </div>

                 <div className="bg-white rounded-[2rem] border border-emerald-100 overflow-hidden shadow-sm relative">
                    <div className="overflow-x-auto custom-scrollbar">
                      <table className="w-full border-collapse">
                        <thead>
                          <tr className="bg-emerald-50/50">
                            <th className="p-4 border-b border-emerald-100"></th>
                            {state.config.workingDays.map(day => (
                              <th key={day} className="p-4 text-[10px] font-black text-emerald-800 uppercase tracking-widest border-b border-l border-emerald-100 min-w-[150px]">{day}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {state.config.timeSlots.map(slot => (
                            <tr key={slot.id}>
                              <td className="p-4 border-b border-emerald-100 bg-emerald-50/30">
                                <p className="text-[10px] font-black text-emerald-900 whitespace-nowrap">{slot.label}</p>
                                <p className="text-[8px] font-bold text-slate-400">{slot.start} - {slot.end}</p>
                              </td>
                              {state.config.workingDays.map(day => {
                                const entry = getEntry(day, slot.id);
                                if (slot.isBreak) return <td key={day} className="p-4 bg-amber-50/30 border-b border-l border-emerald-100 text-center"><i className="fa-solid fa-mug-hot text-amber-200"></i></td>;

                                return (
                                  <td 
                                    key={day} 
                                    onClick={() => setEditingSlot({day, slotId: slot.id})}
                                    className="p-3 border-b border-l border-emerald-100 grid-cell cursor-pointer relative"
                                  >
                                    {entry ? (
                                      <div className="bg-emerald-600 p-3 rounded-xl text-white shadow-sm">
                                        <p className="text-[10px] font-black uppercase mb-1 leading-none">{state.subjects.find(s => s.id === entry.subjectId)?.name}</p>
                                        <p className="text-[8px] font-bold opacity-80 uppercase leading-none">
                                          {gridMode === 'class' 
                                            ? state.staff.find(st => st.id === entry.facultyId)?.name 
                                            : state.classes.find(cl => cl.id === entry.classId)?.name
                                          }
                                        </p>
                                      </div>
                                    ) : (
                                      <div className="flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                                        <i className="fa-solid fa-plus text-emerald-200"></i>
                                      </div>
                                    )}

                                    {editingSlot?.day === day && editingSlot?.slotId === slot.id && (
                                      <div className="absolute inset-0 z-50 bg-white p-2 rounded-xl shadow-2xl border border-emerald-200 flex flex-col gap-2 min-w-[200px]" onClick={e => e.stopPropagation()}>
                                         <div className="flex justify-between items-center px-1">
                                            <span className="text-[8px] font-black text-emerald-600 uppercase">Assignment</span>
                                            <button onClick={() => setEditingSlot(null)} className="text-slate-300 hover:text-red-500"><i className="fa-solid fa-xmark text-[10px]"></i></button>
                                         </div>
                                         <select 
                                          className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2"
                                          defaultValue={entry?.subjectId || ""}
                                          onChange={e => {
                                            const subId = e.target.value;
                                            if (gridMode === 'class') {
                                               const facultyId = (document.getElementById(`facultySelect-${day}-${slot.id}`) as HTMLSelectElement)?.value;
                                               handleAssign(day, slot.id, subId, facultyId, selectedTargetId);
                                            } else {
                                               const classId = (document.getElementById(`classSelect-${day}-${slot.id}`) as HTMLSelectElement)?.value;
                                               handleAssign(day, slot.id, subId, selectedTargetId, classId);
                                            }
                                          }}
                                         >
                                            <option value="">- Clear Slot -</option>
                                            {state.subjects.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                         </select>
                                         {gridMode === 'class' ? (
                                           <select id={`facultySelect-${day}-${slot.id}`} className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2" defaultValue={entry?.facultyId || ""}>
                                              {state.staff.map(st => <option key={st.id} value={st.id}>{st.name}</option>)}
                                           </select>
                                         ) : (
                                           <select id={`classSelect-${day}-${slot.id}`} className="text-[9px] font-bold border-none bg-slate-50 rounded-lg p-2" defaultValue={entry?.classId || ""}>
                                              {state.classes.map(cl => <option key={cl.id} value={cl.id}>{cl.name} ({cl.section})</option>)}
                                           </select>
                                         )}
                                      </div>
                                    )}
                                  </td>
                                );
                              })}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                 </div>
              </div>
            )}

            {/* Omitted other tabs for brevity, they remain as they were */}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

export interface TimeSlot {
  id: string;
  label: string;
  start: string;
  end: string;
  isBreak: boolean;
}

export interface InstitutionConfig {
  workingDays: string[];
  periodsPerDay: number;
  timeSlots: TimeSlot[];
  academicYear: string;
  term: string;
}

export interface TimetableEntry {
  id: string;
  day: string;
  slotId: string;
  subjectId: string;
  facultyId: string;
  classId: string;
  type: 'Lecture' | 'Lab' | 'Seminar' | 'Clinical';
  isLocked?: boolean;
}

export interface StaffMember {
  id: string;
  name: string;
  email: string;
  department: string;
  specialization: string[];
  assignedSubjects: string[]; 
  isActive: boolean;
  availability: string[]; // Days they are available
}

export interface AttendanceRecord {
  id: string;
  staffId: string;
  date: string;
  timestamp: string;
  status: 'Present';
}

export interface LeaveRequest {
  id: string;
  staffId: string;
  startDate: string;
  endDate: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  requestDate: string;
}

export interface Subject {
  id: string;
  code: string;
  name: string;
  department: string;
}

export interface ClassRoom {
  id: string;
  name: string;
  section: string;
}

export interface Substitution {
  id: string;
  date: string;
  slotId: string;
  classId: string;
  originalFacultyId: string;
  substituteFacultyId: string;
  reason: string;
  status: 'Pending' | 'Approved' | 'Cancelled';
}

export interface AdminSettings {
  googleLoginEnabled: boolean;
  approvedEmails: string[];
  googleClientId: string;
  googleClientSecret: string;
  adminUsername: string;
  adminPassword: string;
}

export interface SystemLog {
  id: string;
  timestamp: string;
  user: string;
  action: string;
}

export interface AppState {
  config: InstitutionConfig;
  timetable: TimetableEntry[];
  staff: StaffMember[];
  attendance: AttendanceRecord[];
  leaves: LeaveRequest[];
  subjects: Subject[];
  classes: ClassRoom[];
  substitutions: Substitution[];
  settings: AdminSettings;
  logs: SystemLog[];
}

export interface AnalysisResult {
  summary: string;
