import { TimetableEntry, AnalysisResult, AppState, StaffMember } from "../types";
import { getState } from "./dataStore";

/**
 * Conflict Detection (Pure Local Logic)
 */
export const detectConflicts = (entries: TimetableEntry[]) => {
  const conflicts: { type: string; description: string; severity: string }[] = [];
  const facultyMap = new Map<string, TimetableEntry>();
  const classMap = new Map<string, TimetableEntry>();
  const state = getState();

  entries.forEach(e => {
    const facultyKey = `${e.day}-${e.slotId}-${e.facultyId}`;
    const classKey = `${e.day}-${e.slotId}-${e.classId}`;

    if (facultyMap.has(facultyKey)) {
      const existing = facultyMap.get(facultyKey)!;
      const faculty = state.staff.find(s => s.id === e.facultyId);
      const c1 = state.classes.find(c => c.id === existing.classId)?.name;
      const c2 = state.classes.find(c => c.id === e.classId)?.name;
      conflicts.push({
        type: "Faculty Conflict",
        description: `${faculty?.name || 'Faculty'} has simultaneous sessions for ${c1} and ${c2} on ${e.day}.`,
        severity: "High"
      });
    }
    facultyMap.set(facultyKey, e);

    if (classMap.has(classKey)) {
      const existing = classMap.get(classKey)!;
      if (existing.id !== e.id) {
        const cName = state.classes.find(c => c.id === e.classId)?.name;
        conflicts.push({
          type: "Class Overlap",
          description: `${cName} is assigned multiple subjects at the same time on ${e.day}.`,
          severity: "Medium"
        });
      }
    }
    classMap.set(classKey, e);
  });

  return { conflicts };
};

/**
 * Substitution Suggestion (Pure Matching Logic)
 */
export const suggestSubstitution = async (subjectName: string, reason: string) => {
  const state = getState();
  const subject = state.subjects.find(s => s.name === subjectName);
  const sameDept = state.staff.filter(s => s.isActive && (subject ? s.department === subject.department : true));
  const candidate = sameDept[0] || state.staff.find(s => s.isActive);

  await new Promise(r => setTimeout(r, 400));
  if (!candidate) return "No staff available.";

  return `Recommendation: ${candidate.name} (${candidate.department}). Reason: ${reason}. Logic: Domain matching.`;
};

/**
 * Website Analysis (Keyword-Based Logic)
 */
export const analyzeWebsite = async (url: string): Promise<AnalysisResult> => {
  await new Promise(r => setTimeout(r, 800));
  const isEdu = url.includes('.edu') || url.includes('siddartha') || url.includes('college');

  return {
    summary: isEdu 
      ? `Analysis of ${url}: Academic resource identified. System confirms secure connection to the institution's digital infrastructure. Tools include real-time scheduling and coordination.`
      : `Analysis of ${url}: General web resource identified. Not flagged as a primary academic institutional asset.`,
    sources: [{ uri: url, title: "Resource Link" }]
  };
};

import React, { useState } from 'react';
import { analyzeWebsite } from '../services/geminiService';
import { AnalysisState } from '../types';

const AnalyzerCard: React.FC = () => {
  const [url, setUrl] = useState('siddarthacollegetimetable.bolt.host');
  const [state, setState] = useState<AnalysisState>({
    isLoading: false,
    error: null,
    result: null,
  });

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url) return;
    setState({ isLoading: true, error: null, result: null });
    try {
      const result = await analyzeWebsite(url);
      setState({ isLoading: false, error: null, result });
    } catch (err: any) {
      setState({ isLoading: false, error: err.message || "An unexpected error occurred", result: null });
    }
  };

  const formattedSummary = (text: string) => {
    return text.split('\n').map((line, i) => (
      <p key={i} className="mb-3 text-slate-600 leading-relaxed font-medium">{line}</p>
    ));
  };

  return (
    <div className="max-w-4xl mx-auto mt-12 px-4 mb-20">
      <div className="glass border border-emerald-100 rounded-[3rem] overflow-hidden shadow-2xl">
        <div className="p-10 border-b border-emerald-50 bg-emerald-50/30">
          <h2 className="text-2xl font-black text-emerald-900 mb-1 tracking-tight">Resource Analysis</h2>
          <p className="text-emerald-500 text-[10px] font-black uppercase tracking-widest mb-8">Scan Institutional Assets</p>

          <form onSubmit={handleAnalyze} className="flex flex-col sm:flex-row gap-4">
            <input
              type="text"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="Enter institutional URL..."
              className="flex-grow px-6 py-4 bg-white border border-emerald-100 rounded-2xl text-emerald-900 font-bold placeholder-emerald-200 focus:outline-emerald-500 shadow-inner"
            />
            <button
              type="submit"
              disabled={state.isLoading}
              className={`px-10 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest text-white transition-all ${
                state.isLoading ? 'bg-slate-300' : 'bg-emerald-600 shadow-lg shadow-emerald-200 active:scale-95'
              }`}
            >
              {state.isLoading ? 'Scanning...' : 'Analyze Asset'}
            </button>
          </form>
        </div>

        <div className="p-10 min-h-[200px]">
          {state.isLoading && (
            <div className="flex flex-col items-center justify-center space-y-4 py-12">
               <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
               <p className="text-[10px] font-black text-emerald-600 uppercase">Verifying Resource Integrity...</p>
            </div>
          )}

          {!state.isLoading && state.result && (
            <div className="animate-in fade-in slide-in-from-bottom-4">
              <div className="flex items-center gap-2 mb-6">
                <span className="px-3 py-1 bg-emerald-100 text-emerald-700 text-[8px] font-black uppercase rounded-full">System Verified</span>
              </div>
              <div className="prose prose-emerald">
                {formattedSummary(state.result.summary)}
              </div>
            </div>
          )}

          {!state.isLoading && !state.result && (
            <div className="flex flex-col items-center justify-center text-center space-y-4 py-12 opacity-20">
               <i className="fa-solid fa-microscope text-5xl text-emerald-900"></i>
               <p className="text-[10px] font-black text-emerald-900 uppercase">Input URL to begin validation</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

