export const getState = (): AppState => {
  const data = localStorage.getItem(KEYS.STATE);
  if (!data) return INITIAL_STATE;
  try {
    const parsed = JSON.parse(data);
    if (!parsed.attendance) parsed.attendance = [];
    if (!parsed.leaves) parsed.leaves = [];
    if (!parsed.settings.principalUsername) {
        parsed.settings.principalUsername = DEFAULT_SETTINGS.principalUsername;
        parsed.settings.principalPassword = DEFAULT_SETTINGS.principalPassword;
    }
    return parsed;
  } catch (e) {
    return INITIAL_STATE;
  }
};

export const saveState = (state: AppState) => {
  localStorage.setItem(KEYS.STATE, JSON.stringify(state));
};

export const setSession = (token: string | null, role: 'admin' | 'principal' | null = null) => {
  if (token) {
      localStorage.setItem(KEYS.AUTH, token);
      if (role) localStorage.setItem(KEYS.ROLE, role);
  } else {
      localStorage.removeItem(KEYS.AUTH);
      localStorage.removeItem(KEYS.ROLE);
  }
};

export const getSession = () => localStorage.getItem(KEYS.AUTH);
export const getRole = () => localStorage.getItem(KEYS.ROLE) as 'admin' | 'principal' | null;
export const getSettings = () => getState().settings;
export const getTimetable = () => getState().timetable;

import React, { useState, useEffect } from 'react';
import { getSettings, setSession } from '../../services/dataStore';

const LoginForm: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const settings = getSettings();

  useEffect(() => {
    if (settings.googleLoginEnabled && settings.googleClientId && (window as any).google) {
      (window as any).google.accounts.id.initialize({
        client_id: settings.googleClientId,
        callback: handleGoogleResponse,
      });
      (window as any).google.accounts.id.renderButton(
        document.getElementById("googleBtn"),
        { theme: "outline", size: "large", width: "100%" }
      );
    }
  }, [settings.googleLoginEnabled, settings.googleClientId]);

  const handleGoogleResponse = (response: any) => {
    try {
      const payload = JSON.parse(atob(response.credential.split('.')[1]));
      const userEmail = payload.email;

      if (settings.approvedEmails.includes(userEmail)) {
        setSession('google_token_' + Date.now(), 'admin');
        onLogin();
      } else {
        setError(`Access Denied: ${userEmail} is not on the whitelisted emails.`);
      }
    } catch (err) {
      setError('Google Authentication failed.');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === settings.principalUsername && password === settings.principalPassword) {
      setSession('dummy_token_' + Date.now(), 'principal');
      onLogin();
    } else if (username === settings.adminUsername && password === settings.adminPassword) {
      setSession('dummy_token_' + Date.now(), 'admin');
      onLogin();
    } else {
      setError('Invalid credentials. Access denied.');
    }
  };

  const isGoogleConfigured = settings.googleLoginEnabled && settings.googleClientId;

  return (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl border-emerald-100 text-center animate-in zoom-in duration-300">
        <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-200 mx-auto mb-6">
          <i className="fa-solid fa-shield-halved text-white text-2xl"></i>
        </div>

        <h2 className="text-2xl font-black text-emerald-900 mb-2">Restricted Access</h2>
        <p className="text-emerald-600 text-sm mb-8 font-medium italic">Authenticate as Admin or Principal</p>

        <form onSubmit={handleLogin} className="space-y-4 text-left">
          {error && <p className="text-xs text-red-500 font-bold bg-red-50 p-3 rounded-lg border border-red-100 mb-4">{error}</p>}

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Username</label>
            <input 
              type="text" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500 transition-all" 
              value={username}
              onChange={e => setUsername(e.target.value)}
              required
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Password</label>
            <input 
              type="password" 
              className="w-full px-5 py-3 rounded-2xl bg-white/50 border border-emerald-100 focus:outline-emerald-500 transition-all" 
              value={password}
              onChange={e => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit"
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-bold transition-all shadow-lg shadow-emerald-200 mt-4 active:scale-95"
          >
            Authenticate
          </button>
        </form>

        {isGoogleConfigured && (
          <div className="mt-8 pt-8 border-t border-emerald-100">
            <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest mb-4">Or sign in with SSO</p>
            <div id="googleBtn" className="w-full overflow-hidden rounded-xl"></div>
          </div>
        )}

        <p className="mt-8 text-[10px] text-emerald-300 font-bold uppercase tracking-tight">
          Principal (1234) Access Enabled
        </p>
      </div>
    </div>
  );
};

