  useEffect(() => {
    if (gridMode === 'class' && state.classes.length > 0 && !selectedTargetId) {
      setSelectedTargetId(state.classes[0].id);
    } else if (gridMode === 'staff' && state.staff.length > 0 && !selectedTargetId) {
      setSelectedTargetId(state.staff[0].id);
    }
  }, [gridMode, state.classes, state.staff]);

  const addLog = (action: string) => {
    const newLog: SystemLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      user: userRole === 'principal' ? 'Principal' : state.settings.adminUsername,
      action
    };
    setState(prev => ({ ...prev, logs: [newLog, ...prev.logs].slice(0, 50) }));
  };

  const handleBackup = () => {
    const dataStr = JSON.stringify(state);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `scops_backup_${new Date().toISOString()}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
    addLog('System data backup exported');
  };

  const getEntry = (day: string, slotId: string) => {
    return state.timetable.find(e => 
      e.day === day && 
      e.slotId === slotId && 
      (gridMode === 'class' ? e.classId === selectedTargetId : e.facultyId === selectedTargetId)
    );
  };

  const handleAssign = (day: string, slotId: string, subjectId: string, facultyId: string, classId: string) => {
    const newTimetable = state.timetable.filter(e => 
      !(e.day === day && e.slotId === slotId && (gridMode === 'class' ? e.classId === classId : e.facultyId === facultyId))
    );

    if (subjectId) {
      newTimetable.push({
        id: 'te-' + Date.now(),
        day,
        slotId,
        subjectId,
        facultyId,
        classId,
        type: 'Lecture'
      });
      addLog(`Assigned ${state.subjects.find(s => s.id === subjectId)?.name} to ${day} ${state.config.timeSlots.find(s => s.id === slotId)?.label}`);
    } else {
      addLog(`Cleared slot ${day} ${state.config.timeSlots.find(s => s.id === slotId)?.label}`);
    }

    setState({...state, timetable: newTimetable});
    setEditingSlot(null);
  };

  const handleMarkAttendance = (staffId: string) => {
    const today = new Date().toISOString().split('T')[0];
    const alreadyMarked = state.attendance.some(a => a.staffId === staffId && a.date === today);

    if (alreadyMarked) {
      alert("Attendance already marked for today.");
      return;
    }

    const newRecord: AttendanceRecord = {
      id: Date.now().toString(),
      staffId,
      date: today,
      timestamp: new Date().toLocaleTimeString(),
      status: 'Present'
