    setState(prev => ({ ...prev, leaves: [...prev.leaves, newLeave] }));
    addLog(`Leave record filed for ${state.staff.find(s => s.id === leaveStaffId)?.name}`);
    setLeaveReason('');
    setLeaveStartDate('');
    setLeaveEndDate('');
