                          </div>
                          <div>
                             <p className="text-[8px] font-black uppercase mb-1 ml-1 text-emerald-500">Password</p>
                             <input type="password" value={state.settings.principalPassword} onChange={e => setState({...state, settings: {...state.settings, principalPassword: e.target.value}})} className="w-full p-3 bg-white/10 border-none rounded-xl font-mono text-sm" />
                          </div>
                       </div>
                    </div>

                    <div className="pt-8 border-t border-white/10">
                       <h4 className="text-xs font-black uppercase tracking-[0.2em] text-emerald-400 mb-6">Staff Admin Profile</h4>
                       <div className="grid grid-cols-2 gap-6">
                          <div>
                             <p className="text-[8px] font-black uppercase mb-1 ml-1 text-emerald-500">Username</p>
                             <input type="text" value={state.settings.adminUsername} onChange={e => setState({...state, settings: {...state.settings, adminUsername: e.target.value}})} className="w-full p-3 bg-white/10 border-none rounded-xl font-mono text-sm" />
