                                                    {state.subjects.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                                                 </select>
                                              </div>
                                           )}
                                        </td>
                                      );
                                   })}
                                </tr>
                             ))}
                          </tbody>
