                          <input type="password" value={state.settings.principalPassword} onChange={e => setState({...state, settings: {...state.settings, principalPassword: e.target.value}})} className="p-3 bg-white/10 rounded-xl text-sm border-none" placeholder="Password" />
                       </div>
                    </div>
                    <div>
                       <Label><span className="text-emerald-500">Staff Admin Login</span></Label>
                       <div className="grid grid-cols-2 gap-4 mt-2">
                          <input type="text" value={state.settings.adminUsername} onChange={e => setState({...state, settings: {...state.settings, adminUsername: e.target.value}})} className="p-3 bg-white/10 rounded-xl text-sm border-none" placeholder="Username" />
                          <input type="password" value={state.settings.adminPassword} onChange={e => setState({...state, settings: {...state.settings, adminPassword: e.target.value}})} className="p-3 bg-white/10 rounded-xl text-sm border-none" placeholder="Password" />
                       </div>
                    </div>
                    <button onClick={() => alert("Security settings applied.")} className="w-full py-4 bg-emerald-500 text-emerald-950 font-black rounded-2xl uppercase tracking-widest active:scale-95">Update Security Profile</button>
                 </div>
              </div>
            )}

            {/* SYSTEM TAB (Principal Only) */}
            {activeTab === 'sys' && userRole === 'principal' && (
              <div className="space-y-10 animate-in fade-in">
                 <h3 className="text-2xl font-black text-emerald-900">System Core Control</h3>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="p-10 glass rounded-[3rem] text-center border-emerald-100 hover:shadow-xl transition-all">
