                       <h4 className="text-lg font-black text-emerald-900">Snapshot Export</h4>
                       <button onClick={handleBackup} className="w-full mt-6 py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase">Download State</button>
                    </div>
                    <div className="p-10 glass rounded-[3rem] text-center border-red-50 hover:shadow-xl transition-all">
                       <i className="fa-solid fa-trash-can text-4xl text-red-100 mb-6"></i>
