                       <button onClick={() => { if(confirm("Purge all?")) { localStorage.clear(); window.location.reload(); }}} className="w-full mt-6 py-4 bg-red-500 text-white rounded-2xl font-black text-[10px] uppercase">Hard Factory Reset</button>
                    </div>
                 </div>
              </div>
            )}

            {/* Substitution Logic Placeholder */}
            {activeTab === 'sub' && (
              <div className="space-y-10 animate-in fade-in">
                 <h3 className="text-2xl font-black text-emerald-900">Substitution Engine</h3>
                 <div className="p-20 text-center glass border-dashed border-emerald-100 rounded-[3rem] text-slate-300 italic text-xs">
                    Manual override and logic-based substitution triggers will appear here as entries fail clock-in verification.
                 </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { getState, saveState, getRole } from '../../services/dataStore';
import { AppState, StaffMember, Subject, ClassRoom, TimetableEntry, SystemLog, AttendanceRecord, LeaveRequest } from '../../types';
import { detectConflicts } from '../../services/geminiService';

const Label: React.FC<React.PropsWithChildren<{}>> = ({ children }) => (
  <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest block mb-1.5 ml-1">{children}</label>
);

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [state, setState] = useState<AppState>(getState());
  const [activeTab, setActiveTab] = useState<'monitor' | 'registry' | 'time' | 'sub' | 'attn' | 'leaves' | 'sec' | 'sys'>('monitor');
  const userRole = getRole();

  // Selection state for Monitor
  const [monitorType, setMonitorType] = useState<'staff' | 'class'>('staff');
  const [monitorTargetId, setMonitorTargetId] = useState('');

  // Registry states
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);

  // Timetable Grid states
  const [gridMode, setGridMode] = useState<'class' | 'staff'>('class');
  const [selectedGridTargetId, setSelectedGridTargetId] = useState('');
  const [editingSlot, setEditingSlot] = useState<{day: string, slotId: string} | null>(null);

  // Leave Form State
  const [leaveStaffId, setLeaveStaffId] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [leaveStartDate, setLeaveStartDate] = useState('');
  const [leaveEndDate, setLeaveEndDate] = useState('');

  // Security Section - Temp state for new email
  const [newEmail, setNewEmail] = useState('');

  useEffect(() => {
    saveState(state);
  }, [state]);

  useEffect(() => {
    // Default selections
    if (!monitorTargetId) {
      if (monitorType === 'staff' && state.staff.length > 0) setMonitorTargetId(state.staff[0].id);
      else if (monitorType === 'class' && state.classes.length > 0) setMonitorTargetId(state.classes[0].id);
    }
  }, [monitorType, state.staff, state.classes]);

  useEffect(() => {
    if (gridMode === 'class' && state.classes.length > 0 && !selectedGridTargetId) {
      setSelectedGridTargetId(state.classes[0].id);
    } else if (gridMode === 'staff' && state.staff.length > 0 && !selectedGridTargetId) {
      setSelectedGridTargetId(state.staff[0].id);
    }
  }, [gridMode, state.classes, state.staff]);

  const addLog = (action: string) => {
    const newLog: SystemLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      user: userRole === 'principal' ? 'Principal' : 'Admin',
      action
    };
    setState(prev => ({ ...prev, logs: [newLog, ...prev.logs].slice(0, 50) }));
  };

  const handleBackup = () => {
    const dataStr = JSON.stringify(state);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', `scops_backup_${new Date().toISOString()}.json`);
    linkElement.click();
    addLog('System data backup exported');
  };

  const handleAssign = (day: string, slotId: string, subjectId: string, facultyId: string, classId: string) => {
    const newTimetable = state.timetable.filter(e => 
      !(e.day === day && e.slotId === slotId && (gridMode === 'class' ? e.classId === classId : e.facultyId === facultyId))
    );
    if (subjectId) {
      newTimetable.push({
        id: 'te-' + Date.now(),
        day, slotId, subjectId, facultyId, classId, type: 'Lecture'
      });
      addLog(`Modified timetable for ${day} ${slotId}`);
    }
    setState({...state, timetable: newTimetable});
    setEditingSlot(null);
  };

  const handleMarkAttendance = (staffId: string) => {
    const today = new Date().toISOString().split('T')[0];
    if (state.attendance.some(a => a.staffId === staffId && a.date === today)) {
      alert("Attendance already marked.");
      return;
    }
    const newRecord: AttendanceRecord = {
      id: Date.now().toString(),
      staffId,
      date: today,
      timestamp: new Date().toLocaleTimeString(),
      status: 'Present'
    };
    setState(prev => ({ ...prev, attendance: [...prev.attendance, newRecord] }));
    addLog(`Attendance marked for ${state.staff.find(s => s.id === staffId)?.name}`);
  };

  const handleApplyLeave = () => {
    if (!leaveStaffId || !leaveReason || !leaveStartDate || !leaveEndDate) {
      alert("Fill all fields.");
      return;
    }
    const newLeave: LeaveRequest = {
      id: 'leave-' + Date.now(),
      staffId: leaveStaffId,
      startDate: leaveStartDate,
      endDate: leaveEndDate,
      reason: leaveReason,
      status: 'Pending',
      requestDate: new Date().toISOString().split('T')[0]
    };
    setState(prev => ({ ...prev, leaves: [...prev.leaves, newLeave] }));
    addLog(`Leave requested by ${state.staff.find(s => s.id === leaveStaffId)?.name}`);
    setLeaveReason('');
    setLeaveStaffId('');
    alert("Leave request submitted to Principal.");
  };

