             <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white text-xl mb-4 shadow-lg">
                <i className={`fa-solid ${userRole === 'principal' ? 'fa-crown' : 'fa-user-shield'}`}></i>
             </div>
             <h2 className="text-xl font-black text-emerald-900 leading-none tracking-tighter">{userRole?.toUpperCase()} GATEWAY</h2>
             <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mt-1">Siddartha Core v5.5</p>
          </div>

          <nav className="space-y-1">
            {filteredTabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold transition-all ${
                  activeTab === tab.id ? 'bg-emerald-600 text-white shadow-xl' : 'text-emerald-800 hover:bg-emerald-50'
                }`}
              >
                <i className={`fa-solid ${tab.icon} w-5`}></i>
                <span className="text-[10px] uppercase tracking-widest">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button onClick={onLogout} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-10 transition-all">
            <i className="fa-solid fa-power-off w-5"></i>
            <span className="text-[10px] uppercase tracking-widest">Terminate Session</span>
          </button>
        </aside>

        {/* Content Area */}
        <div className="flex-grow">
          <div className="glass rounded-[3rem] p-10 min-h-[800px] border-emerald-100 shadow-2xl relative overflow-hidden">

            {/* 1. MONITOR TAB */}
            {activeTab === 'monitor' && (
              <div className="space-y-10 animate-in fade-in">
                <div>
                   <h3 className="text-2xl font-black text-emerald-900">Live Asset Monitoring</h3>
                   <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Select target entity for real-time synchronization</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-8 bg-emerald-50 rounded-[2.5rem] border border-emerald-100">
                   <div>
                      <Label>Target Entity Type</Label>
                      <div className="flex bg-white rounded-2xl p-1 shadow-sm">
                        <button 
                          onClick={() => { setMonitorType('staff'); setMonitorTargetId(''); }}
                          className={`flex-grow py-3 rounded-xl text-[10px] font-black uppercase transition-all ${monitorType === 'staff' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400'}`}
                        >Staff Member</button>
