import React, { useState, useEffect } from 'react';
import { getSettings, setSession } from '../../services/dataStore';

const LoginForm: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const settings = getSettings();

  useEffect(() => {
    if (settings.googleLoginEnabled && settings.googleClientId && (window as any).google) {
      (window as any).google.accounts.id.initialize({
        client_id: settings.googleClientId,
        callback: handleGoogleResponse,
      });
      (window as any).google.accounts.id.renderButton(
        document.getElementById("googleBtn"),
        { theme: "outline", size: "large", width: "100%" }
      );
    }
  }, [settings.googleLoginEnabled, settings.googleClientId]);

  const handleGoogleResponse = (response: any) => {
    try {
      const payload = JSON.parse(atob(response.credential.split('.')[1]));
      const userEmail = payload.email;

      // Google Login is strictly for Admin role access
      if (settings.approvedEmails.includes(userEmail)) {
        setSession('google_token_' + Date.now(), 'admin');
        onLogin();
      } else {
        setError(`Access Denied: ${userEmail} is not in the authorized Admin whitelist.`);
      }
    } catch (err) {
      setError('Google identity verification failed.');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === settings.principalUsername && password === settings.principalPassword) {
      setSession('dummy_token_' + Date.now(), 'principal');
      onLogin();
    } else if (username === settings.adminUsername && password === settings.adminPassword) {
      setSession('dummy_token_' + Date.now(), 'admin');
      onLogin();
    } else {
      setError('Invalid identity credentials. Access denied.');
    }
  };

  const isGoogleConfigured = settings.googleLoginEnabled && settings.googleClientId;

  return (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl border-emerald-100 text-center animate-in zoom-in duration-300">
        <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-200 mx-auto mb-6">
          <i className="fa-solid fa-key text-white text-2xl"></i>
        </div>

        <h2 className="text-2xl font-black text-emerald-900 mb-2 leading-tight">Identity Verification</h2>
        <p className="text-emerald-600 text-[10px] mb-8 font-black uppercase tracking-widest">Authorized Core Access Only</p>

        <form onSubmit={handleLogin} className="space-y-4 text-left">
          {error && <p className="text-[10px] text-red-500 font-black bg-red-50 p-4 rounded-2xl border border-red-100 mb-4 uppercase tracking-tight">{error}</p>}

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Universal Username</label>
            <input 
              type="text" 
              className="w-full px-6 py-4 rounded-2xl bg-white border border-emerald-50 focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all shadow-inner" 
              value={username}
              onChange={e => setUsername(e.target.value)}
              required
              placeholder="1234..."
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest ml-1">Secret Keyphrase</label>
            <input 
              type="password" 
              className="w-full px-6 py-4 rounded-2xl bg-white border border-emerald-50 focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all shadow-inner" 
              value={password}
              onChange={e => setPassword(e.target.value)}
              required
              placeholder="••••••••"
            />
          </div>

          <button 
            type="submit"
            className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all shadow-lg shadow-emerald-200 mt-6 active:scale-95"
          >
            Decrypt Access
          </button>
        </form>

        {isGoogleConfigured && (
          <div className="mt-8 pt-8 border-t border-emerald-50">
            <p className="text-[10px] font-black text-emerald-400 uppercase tracking-widest mb-4">SSO Entry (Staff Admin Only)</p>
            <div id="googleBtn" className="w-full overflow-hidden rounded-2xl transition-all active:scale-95"></div>
          </div>
        )}

        <div className="mt-8 p-4 bg-emerald-50/50 rounded-2xl border border-emerald-50">
           <p className="text-[9px] text-emerald-400 font-black uppercase tracking-tighter">
             Security Protocol: Principal authority bypass disabled for SSO.
           </p>
        </div>
      </div>
    </div>
  );
};

