import { AppState } from "../types";

/**
 * Raw REST logic for Google Sheets integration via Apps Script Web App.
 * No AI, just deterministic HTTP communication.
 */
export const syncToCloud = async (url: string, state: AppState): Promise<boolean> => {
  if (!url) return false;
  try {
    const response = await fetch(url, {
      method: 'POST',
      mode: 'no-cors', // Apps Script requires no-cors for simple redirects
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(state),
    });
    return true; 
  } catch (error) {
    console.error("Cloud Sync Failed:", error);
    return false;
  }
};

export const fetchFromCloud = async (url: string): Promise<AppState | null> => {
  if (!url) return null;
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error("Network response was not ok");
    const data = await response.json();
    return data as AppState;
  } catch (error) {
    console.error("Cloud Fetch Failed:", error);
    return null;
  }
};

