import { AppState } from "../types";

/**
 * Optimized REST logic for Google Sheets integration.
 * Uses 'text/plain' to avoid CORS preflight (OPTIONS) which Google Apps Script doesn't support.
 */
export const syncToCloud = async (url: string, state: AppState): Promise<boolean> => {
  if (!url) return false;
  try {
    // We send as text/plain to avoid CORS preflight issues
    await fetch(url, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 
        'Content-Type': 'text/plain;charset=utf-8' 
      },
      body: JSON.stringify(state),
    });
    // With no-cors, we can't read the response, so we assume success if no exception occurred
    return true; 
  } catch (error) {
    console.error("Cloud Sync Failed:", error);
    return false;
  }
};

export const fetchFromCloud = async (url: string): Promise<AppState | null> => {
  if (!url) return null;
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error("Network response was not ok");
    const data = await response.json();

    // Validate that the returned data is a valid state object
    if (data && typeof data === 'object' && (data.config || data.settings)) {
      return data as AppState;
    }
    return null;
  } catch (error) {
    console.error("Cloud Fetch Failed:", error);
    return null;
  }
};

