      staff: type === 'staff' ? prev.staff.filter(i => i.id !== id) : prev.staff,
      subjects: type === 'subject' ? prev.subjects.filter(i => i.id !== id) : prev.subjects,
      classes: type === 'class' ? prev.classes.filter(i => i.id !== id) : prev.classes,
    }));
  };

  // --- TIMETABLE HANDLERS ---
  const handleAssignSlot = (slotId: string, facultyId: string, subjectId: string, type: any) => {
    if (!gridClassId) return;

    const newEntry: TimetableEntry = {
      id: Date.now().toString(),
      day: selectedDay,
      slotId,
      classId: gridClassId,
      facultyId,
      subjectId,
      type
    };

    // Conflict Check
    const tempEntries = [...state.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId)), newEntry];
    const { conflicts } = detectConflicts(tempEntries);

    if (conflicts.length > 0) {
      if (!confirm(`Warning: ${conflicts[0].description}\n\nProceed anyway?`)) return;
    }

    setState(prev => ({
      ...prev,
      timetable: tempEntries
    }));
    setEditingSlot(null);
    addLog(`Updated Timetable: ${selectedDay} Slot ${slotId}`);
  };

  const clearSlot = (slotId: string) => {
    setState(prev => ({
      ...prev,
      timetable: prev.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId))
    }));
  };

  const allTabs = [
    { id: 'monitor', icon: 'fa-chart-line', label: 'Monitoring' },
    { id: 'registry', icon: 'fa-address-book', label: 'Registry' },
    { id: 'time', icon: 'fa-calendar-check', label: 'Timetables' },
    { id: 'attn', icon: 'fa-clipboard-user', label: 'Attendance' },
    { id: 'leaves', icon: 'fa-calendar-day', label: 'Leaves' },
    { id: 'sec', icon: 'fa-shield-halved', label: 'Security', principal: true },
    { id: 'sys', icon: 'fa-sliders', label: 'System', principal: true }
  ];

  const filteredTabs = allTabs.filter(t => userRole === 'principal' || !t.principal);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* Sidebar */}
        <aside className="lg:w-72 space-y-2">
          <div className="p-8 mb-6 glass rounded-[2.5rem] border-emerald-100 shadow-xl relative overflow-hidden">
             <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white text-xl mb-4 shadow-lg">
                <i className={`fa-solid ${userRole === 'principal' ? 'fa-crown' : 'fa-user-shield'}`}></i>
             </div>
             <h2 className="text-xl font-black text-emerald-900 leading-none tracking-tighter">{userRole?.toUpperCase()} CORE</h2>
             <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mt-1">Siddartha Portal v5.8</p>
          </div>

          <nav className="space-y-1">
            {filteredTabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold transition-all ${
                  activeTab === tab.id ? 'bg-emerald-600 text-white shadow-xl' : 'text-emerald-800 hover:bg-emerald-50'
