                <i className={`fa-solid ${tab.icon} w-5`}></i>
                <span className="text-[10px] uppercase tracking-widest">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button onClick={onLogout} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-10 transition-all">
            <i className="fa-solid fa-power-off w-5"></i>
            <span className="text-[10px] uppercase tracking-widest">Logout</span>
          </button>
        </aside>

        {/* Content Area */}
        <div className="flex-grow">
          <div className="glass rounded-[3rem] p-10 min-h-[800px] border-emerald-100 shadow-2xl relative overflow-hidden">

            {/* MONITOR TAB */}
            {activeTab === 'monitor' && (
               <div className="space-y-10 animate-in fade-in">
                  <h3 className="text-2xl font-black text-emerald-900 uppercase tracking-tight">System Monitor</h3>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                     <div className="p-8 bg-emerald-50 rounded-3xl border border-emerald-100">
                        <p className="text-[10px] font-black text-emerald-600 uppercase mb-2">Total Faculty</p>
                        <p className="text-4xl font-black text-emerald-900">{state.staff.length}</p>
                     </div>
                     <div className="p-8 bg-blue-50 rounded-3xl border border-blue-100">
                        <p className="text-[10px] font-black text-blue-600 uppercase mb-2">Classes Configured</p>
                        <p className="text-4xl font-black text-blue-900">{state.classes.length}</p>
                     </div>
                     <div className="p-8 bg-purple-50 rounded-3xl border border-purple-100">
                        <p className="text-[10px] font-black text-purple-600 uppercase mb-2">Live Logs</p>
                        <p className="text-4xl font-black text-purple-900">{state.logs.length}</p>
                     </div>
                  </div>
                  <div className="space-y-4">
                     <Label>Recent Activity Stream</Label>
                     <div className="bg-slate-50 border border-slate-100 rounded-3xl p-6 h-64 overflow-y-auto custom-scrollbar">
                        {state.logs.map(log => (
                          <div key={log.id} className="flex justify-between items-center py-3 border-b border-slate-200 last:border-0">
                             <span className="text-[10px] font-bold text-slate-400">{log.timestamp}</span>
                             <span className="text-xs font-bold text-emerald-900">{log.action}</span>
                             <span className="text-[9px] font-black text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-full uppercase">{log.user}</span>
                          </div>
                        ))}
                     </div>
                  </div>
               </div>
            )}

            {/* REGISTRY TAB */}
            {activeTab === 'registry' && (
