                                        <Label>Faculty Member</Label>
                                        <select id={`fac-${slot.id}`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold text-emerald-900">
                                          {state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                        </select>
                                     </div>
                                     <div>
                                        <Label>Subject</Label>
                                        <select id={`sub-${slot.id}`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold text-emerald-900">
                                          {state.subjects.map(s => <option key={s.id} value={s.id}>{s.name} ({s.code})</option>)}
                                        </select>
                                     </div>
                                     <div>
                                        <Label>Session Type</Label>
                                        <select id={`type-${slot.id}`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold text-emerald-900">
                                          <option>Lecture</option>
                                          <option>Lab</option>
                                          <option>Seminar</option>
                                          <option>Clinical</option>
                                        </select>
                                     </div>
                                     <div className="flex gap-4 pt-4">
                                        <button onClick={() => {
                                          const fId = (document.getElementById(`fac-${slot.id}`) as HTMLSelectElement).value;
                                          const sId = (document.getElementById(`sub-${slot.id}`) as HTMLSelectElement).value;
                                          const type = (document.getElementById(`type-${slot.id}`) as HTMLSelectElement).value;
                                          handleAssignSlot(slot.id, fId, sId, type);
                                        }} className="flex-grow py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-emerald-200">Save Allocation</button>
                                        <button onClick={() => setEditingSlot(null)} className="px-8 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black text-[10px] uppercase tracking-widest">Cancel</button>
                                     </div>
                                  </div>
                               </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            )}

            {/* ATTENDANCE TAB */}
            {activeTab === 'attn' && (
              <div className="space-y-10 animate-in fade-in">
                 <div>
                    <h3 className="text-2xl font-black text-emerald-900 uppercase tracking-tight">Faculty Presence Check</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Recording for {new Date().toLocaleDateString()}</p>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {state.staff.map(s => {
                      const isPresent = state.attendance.some(a => a.staffId === s.id && a.date === new Date().toISOString().split('T')[0]);
                      return (
                        <div key={s.id} className={`p-6 rounded-[2rem] border transition-all flex justify-between items-center ${isPresent ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                           <div>
                              <p className="text-sm font-black text-emerald-900">{s.name}</p>
                              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{s.department}</p>
                           </div>
                           <button onClick={() => {
                             if(isPresent) return;
                             const record: AttendanceRecord = { id: Date.now().toString(), staffId: s.id, date: new Date().toISOString().split('T')[0], timestamp: new Date().toLocaleTimeString(), status: 'Present' };
                             setState(prev => ({ ...prev, attendance: [...prev.attendance, record] }));
                             addLog(`Attendance Marked: ${s.name}`);
                           }} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isPresent ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-100 text-slate-300 hover:text-emerald-600'}`}>
                              <i className="fa-solid fa-check"></i>
                           </button>
                        </div>
                      );
                    })}
                 </div>
              </div>
