                          <button onClick={handleCloudPull} disabled={isSyncing} className="flex-grow py-4 bg-white border border-emerald-100 text-emerald-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-50 transition-all">
                             Pull from Sheet
                          </button>
                       </div>
                    </div>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="p-10 glass rounded-[3rem] text-center border-emerald-100">
                       <i className="fa-solid fa-download text-4xl text-emerald-300 mb-6"></i>
                       <h4 className="text-lg font-black text-emerald-900 uppercase">Snapshot</h4>
                       <button onClick={handleBackup} className="w-full mt-6 py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest">Export Core JSON</button>
                    </div>
                    <div className="p-10 glass rounded-[3rem] text-center border-red-50">
                       <i className="fa-solid fa-radiation text-4xl text-red-100 mb-6"></i>
                       <h4 className="text-lg font-black text-red-900 uppercase">Emergency Purge</h4>
                       <button onClick={() => { if(confirm("TOTAL PURGE?")) { localStorage.clear(); window.location.reload(); }}} className="w-full mt-6 py-4 bg-red-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest">Wipe Local Storage</button>
                    </div>
                 </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { getState, saveState, getRole } from '../../services/dataStore';
import { AppState, StaffMember, Subject, ClassRoom, TimetableEntry, SystemLog, AttendanceRecord, LeaveRequest, Substitution } from '../../types';
import { detectConflicts } from '../../services/geminiService';
import { syncToCloud, fetchFromCloud } from '../../services/googleSheetsService';

const Label: React.FC<React.PropsWithChildren<{}>> = ({ children }) => (
  <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest block mb-1.5 ml-1">{children}</label>
);

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [state, setState] = useState<AppState>(getState());
  const [activeTab, setActiveTab] = useState<'monitor' | 'registry' | 'time' | 'attn' | 'leaves' | 'sec' | 'sys'>('monitor');
  const [isSyncing, setIsSyncing] = useState(false);
  const userRole = getRole();

  // Registry States
  const [regMode, setRegMode] = useState<'staff' | 'subject' | 'class'>('staff');

  // Timetable Grid states
  const [selectedDay, setSelectedDay] = useState('Monday');
  const [gridClassId, setGridClassId] = useState('');
  const [editingSlot, setEditingSlot] = useState<string | null>(null);

  useEffect(() => {
    saveState(state);
    if (state.settings.cloudDbEnabled && state.settings.googleSheetWebAppUrl) {
      syncToCloud(state.settings.googleSheetWebAppUrl, state);
    }
  }, [state]);

  const addLog = (action: string) => {
    const newLog: SystemLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      user: userRole === 'principal' ? 'Principal' : 'Admin',
      action
    };
    setState(prev => ({ ...prev, logs: [newLog, ...prev.logs].slice(0, 50) }));
  };

  // --- REGISTRY HANDLERS ---
  const addStaff = () => {
    const name = prompt("Enter Staff Name:");
    if (!name) return;
    const newStaff: StaffMember = {
      id: 's' + Date.now(),
      name,
      email: name.toLowerCase().replace(' ', '.') + '@siddartha.edu',
      department: 'Pharmaceutics',
      specialization: [],
      assignedSubjects: [],
      isActive: true,
      availability: state.config.workingDays
    };
    setState(prev => ({ ...prev, staff: [...prev.staff, newStaff] }));
    addLog(`Added Staff: ${name}`);
  };

  const addSubject = () => {
    const name = prompt("Enter Subject Name:");
    const code = prompt("Enter Subject Code:");
    if (!name || !code) return;
    const newSub: Subject = { id: 'sub' + Date.now(), name, code, department: 'Pharmacy' };
    setState(prev => ({ ...prev, subjects: [...prev.subjects, newSub] }));
    addLog(`Added Subject: ${name}`);
  };

  const addClass = () => {
    const name = prompt("Enter Class Name (e.g. B.Pharm Year 1):");
    const section = prompt("Enter Section:");
    if (!name || !section) return;
    const newClass: ClassRoom = { id: 'c' + Date.now(), name, section };
    setState(prev => ({ ...prev, classes: [...prev.classes, newClass] }));
    addLog(`Added Class: ${name} (${section})`);
  };

  const deleteItem = (type: 'staff' | 'subject' | 'class', id: string) => {
    if (!confirm("Are you sure? This may affect existing timetables.")) return;
    setState(prev => ({
      ...prev,
      staff: type === 'staff' ? prev.staff.filter(i => i.id !== id) : prev.staff,
      subjects: type === 'subject' ? prev.subjects.filter(i => i.id !== id) : prev.subjects,
      classes: type === 'class' ? prev.classes.filter(i => i.id !== id) : prev.classes,
    }));
  };

  // --- TIMETABLE HANDLERS ---
  const handleAssignSlot = (slotId: string, facultyId: string, subjectId: string, type: any) => {
    if (!gridClassId) return;

    const newEntry: TimetableEntry = {
      id: Date.now().toString(),
      day: selectedDay,
      slotId,
      classId: gridClassId,
      facultyId,
      subjectId,
      type
    };

    // Conflict Check
    const tempEntries = [...state.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId)), newEntry];
    const { conflicts } = detectConflicts(tempEntries);

    if (conflicts.length > 0) {
      if (!confirm(`Warning: ${conflicts[0].description}\n\nProceed anyway?`)) return;
    }

    setState(prev => ({
      ...prev,
      timetable: tempEntries
    }));
    setEditingSlot(null);
    addLog(`Updated Timetable: ${selectedDay} Slot ${slotId}`);
  };

  const clearSlot = (slotId: string) => {
    setState(prev => ({
      ...prev,
      timetable: prev.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId))
    }));
  };

  // --- SYSTEM HANDLERS ---
  // Added handleManualSync to fix the missing name error on line 489
  const handleManualSync = async () => {
    if (!state.settings.googleSheetWebAppUrl) return;
    setIsSyncing(true);
    try {
      const success = await syncToCloud(state.settings.googleSheetWebAppUrl, state);
      if (success) {
        addLog("Manual Cloud Push Successful");
        alert("Cloud synchronization complete.");
      } else {
        addLog("Manual Cloud Push Failed");
        alert("Cloud push failed. Check URL or network.");
      }
    } catch (err) {
      addLog("Cloud Push Error");
    } finally {
      setIsSyncing(false);
    }
  };

  // Added handleCloudPull to fix the missing name error on line 492
  const handleCloudPull = async () => {
    if (!state.settings.googleSheetWebAppUrl) return;
    if (!confirm("This will overwrite your current local timetable data with the version from Google Sheets. Continue?")) return;

    setIsSyncing(true);
    try {
      const data = await fetchFromCloud(state.settings.googleSheetWebAppUrl);
      if (data) {
        setState(data);
        saveState(data);
        addLog("Data pulled from Cloud successfully");
        alert("Data synchronized from cloud.");
      } else {
        addLog("Cloud Pull Failed: Invalid data received");
        alert("Could not fetch valid data from the cloud.");
      }
    } catch (err) {
      addLog("Cloud Pull Error");
      alert("Error fetching from cloud.");
    } finally {
      setIsSyncing(false);
    }
  };

  // Added handleBackup to fix the missing name error on line 502
  const handleBackup = () => {
    try {
      const blob = new Blob([JSON.stringify(state, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `KVSR_SCOPS_Backup_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      addLog("System State Exported (Backup)");
    } catch (err) {
      addLog("Backup Export Failed");
    }
  };

  const allTabs = [
    { id: 'monitor', icon: 'fa-chart-line', label: 'Monitoring' },
    { id: 'registry', icon: 'fa-address-book', label: 'Registry' },
    { id: 'time', icon: 'fa-calendar-check', label: 'Timetables' },
    { id: 'attn', icon: 'fa-clipboard-user', label: 'Attendance' },
    { id: 'leaves', icon: 'fa-calendar-day', label: 'Leaves' },
    { id: 'sec', icon: 'fa-shield-halved', label: 'Security', principal: true },
    { id: 'sys', icon: 'fa-sliders', label: 'System', principal: true }
  ];

  const filteredTabs = allTabs.filter(t => userRole === 'principal' || !t.principal);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* Sidebar */}
        <aside className="lg:w-72 space-y-2">
          <div className="p-8 mb-6 glass rounded-[2.5rem] border-emerald-100 shadow-xl relative overflow-hidden">
             <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white text-xl mb-4 shadow-lg">
                <i className={`fa-solid ${userRole === 'principal' ? 'fa-crown' : 'fa-user-shield'}`}></i>
             </div>
             <h2 className="text-xl font-black text-emerald-900 leading-none tracking-tighter">{userRole?.toUpperCase()} CORE</h2>
             <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mt-1">Siddartha Portal v5.8</p>
          </div>

          <nav className="space-y-1">
            {filteredTabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold transition-all ${
                  activeTab === tab.id ? 'bg-emerald-600 text-white shadow-xl' : 'text-emerald-800 hover:bg-emerald-50'
                }`}
              >
                <i className={`fa-solid ${tab.icon} w-5`}></i>
                <span className="text-[10px] uppercase tracking-widest">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button onClick={onLogout} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-10 transition-all">
            <i className="fa-solid fa-power-off w-5"></i>
            <span className="text-[10px] uppercase tracking-widest">Logout</span>
          </button>
        </aside>

        {/* Content Area */}
        <div className="flex-grow">
          <div className="glass rounded-[3rem] p-10 min-h-[800px] border-emerald-100 shadow-2xl relative overflow-hidden">

            {/* MONITOR TAB */}
            {activeTab === 'monitor' && (
               <div className="space-y-10 animate-in fade-in">
                  <h3 className="text-2xl font-black text-emerald-900 uppercase tracking-tight">System Monitor</h3>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                     <div className="p-8 bg-emerald-50 rounded-3xl border border-emerald-100">
                        <p className="text-[10px] font-black text-emerald-600 uppercase mb-2">Total Faculty</p>
                        <p className="text-4xl font-black text-emerald-900">{state.staff.length}</p>
                     </div>
                     <div className="p-8 bg-blue-50 rounded-3xl border border-blue-100">
                        <p className="text-[10px] font-black text-blue-600 uppercase mb-2">Classes Configured</p>
                        <p className="text-4xl font-black text-blue-900">{state.classes.length}</p>
                     </div>
                     <div className="p-8 bg-purple-50 rounded-3xl border border-purple-100">
                        <p className="text-[10px] font-black text-purple-600 uppercase mb-2">Live Logs</p>
                        <p className="text-4xl font-black text-purple-900">{state.logs.length}</p>
                     </div>
                  </div>
                  <div className="space-y-4">
                     <Label>Recent Activity Stream</Label>
                     <div className="bg-slate-50 border border-slate-100 rounded-3xl p-6 h-64 overflow-y-auto custom-scrollbar">
                        {state.logs.map(log => (
                          <div key={log.id} className="flex justify-between items-center py-3 border-b border-slate-200 last:border-0">
                             <span className="text-[10px] font-bold text-slate-400">{log.timestamp}</span>
                             <span className="text-xs font-bold text-emerald-900">{log.action}</span>
                             <span className="text-[9px] font-black text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-full uppercase">{log.user}</span>
                          </div>
                        ))}
                     </div>
                  </div>
               </div>
            )}

            {/* REGISTRY TAB */}
            {activeTab === 'registry' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-end">
                  <div>
                    <h3 className="text-2xl font-black text-emerald-900 uppercase tracking-tight">Institutional Registry</h3>
                    <div className="flex gap-4 mt-4">
                      {['staff', 'subject', 'class'].map(m => (
                        <button key={m} onClick={() => setRegMode(m as any)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${regMode === m ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500'}`}>
                          {m}s
                        </button>
                      ))}
                    </div>
                  </div>
                  <button onClick={() => regMode === 'staff' ? addStaff() : regMode === 'subject' ? addSubject() : addClass()} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-emerald-200 active:scale-95 transition-all">
                    Add New {regMode}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {regMode === 'staff' && state.staff.map(s => (
                    <div key={s.id} className="p-6 bg-white border border-emerald-50 rounded-3xl flex justify-between items-center shadow-sm hover:shadow-md transition-all">
                      <div>
                        <p className="text-sm font-black text-emerald-900">{s.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">{s.department}</p>
                      </div>
                      <button onClick={() => deleteItem('staff', s.id)} className="text-red-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can"></i></button>
                    </div>
                  ))}
                  {regMode === 'subject' && state.subjects.map(s => (
                    <div key={s.id} className="p-6 bg-white border border-emerald-50 rounded-3xl flex justify-between items-center shadow-sm hover:shadow-md transition-all">
                      <div>
                        <p className="text-sm font-black text-emerald-900">{s.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">{s.code}</p>
                      </div>
                      <button onClick={() => deleteItem('subject', s.id)} className="text-red-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can"></i></button>
                    </div>
                  ))}
                  {regMode === 'class' && state.classes.map(c => (
                    <div key={c.id} className="p-6 bg-white border border-emerald-50 rounded-3xl flex justify-between items-center shadow-sm hover:shadow-md transition-all">
                      <div>
                        <p className="text-sm font-black text-emerald-900">{c.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Section {c.section}</p>
                      </div>
                      <button onClick={() => deleteItem('class', c.id)} className="text-red-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can"></i></button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* TIMETABLES TAB */}
            {activeTab === 'time' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                  <div className="flex-grow max-w-sm">
                    <Label>Select Class to Edit</Label>
                    <select value={gridClassId} onChange={e => setGridClassId(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-[11px] font-bold text-emerald-900">
                      <option value="">Choose Class...</option>
                      {state.classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.section})</option>)}
                    </select>
                  </div>
                  <div className="flex bg-slate-100 p-1 rounded-2xl">
                    {state.config.workingDays.map(d => (
                      <button key={d} onClick={() => setSelectedDay(d)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${selectedDay === d ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}>
                        {d.substring(0,3)}
                      </button>
                    ))}
                  </div>
                </div>

                {!gridClassId ? (
                  <div className="p-20 text-center text-slate-300 font-black uppercase text-xs">Select a class to view its matrix</div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {state.config.timeSlots.map(slot => {
                      const entry = state.timetable.find(e => e.day === selectedDay && e.slotId === slot.id && e.classId === gridClassId);
                      if (slot.isBreak) return <div key={slot.id} className="p-6 bg-amber-50 border border-amber-100 rounded-3xl text-center text-[10px] font-black text-amber-600 uppercase">{slot.label}</div>;

                      return (
                        <div key={slot.id} className={`p-8 rounded-[2.5rem] border transition-all cursor-pointer relative group ${entry ? 'bg-emerald-600 text-white border-emerald-700 shadow-xl' : 'bg-white border-slate-100 hover:border-emerald-200 shadow-sm'}`} onClick={() => setEditingSlot(slot.id)}>
                          <p className={`text-[9px] font-black uppercase mb-1 ${entry ? 'text-emerald-200' : 'text-emerald-600'}`}>{slot.label}</p>
                          <p className={`text-[10px] font-bold mb-4 ${entry ? 'text-emerald-100/60' : 'text-slate-400'}`}>{slot.start} - {slot.end}</p>

                          {entry ? (
                            <>
                              <p className="text-sm font-black leading-tight mb-2">{state.subjects.find(s => s.id === entry.subjectId)?.name}</p>
                              <p className="text-[10px] font-bold opacity-80 uppercase tracking-widest">{state.staff.find(s => s.id === entry.facultyId)?.name}</p>
                              <button onClick={(e) => { e.stopPropagation(); clearSlot(slot.id); }} className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity"><i className="fa-solid fa-xmark"></i></button>
                            </>
                          ) : (
                            <p className="text-[9px] font-black text-slate-300 uppercase italic">Empty Slot</p>
                          )}

                          {editingSlot === slot.id && (
                            <div className="fixed inset-0 z-[100] bg-emerald-950/80 backdrop-blur-sm flex items-center justify-center p-6" onClick={(e) => e.stopPropagation()}>
