                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Pending Requests Queue</p>
                 </div>
                 <div className="space-y-4">
                    {state.leaves.length === 0 ? (
                      <div className="p-20 text-center text-slate-200 italic font-bold">No pending leave requests.</div>
                    ) : (
                      state.leaves.map(req => (
                        <div key={req.id} className="p-8 bg-white border border-slate-100 rounded-[2.5rem] flex flex-col md:flex-row justify-between items-start md:items-center gap-6 shadow-sm">
                           <div className="space-y-2">
