            {activeTab === 'registry' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-end">
                  <div>
                    <h3 className="text-2xl font-black text-emerald-900 uppercase tracking-tight">Registry</h3>
                    <div className="flex gap-4 mt-4">
                      {['staff', 'subject', 'class'].map(m => (
                        <button key={m} onClick={() => setRegMode(m as any)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${regMode === m ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500'}`}>{m}s</button>
                      ))}
                    </div>
                  </div>
                  <button onClick={addStaff} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-emerald-200">Add New</button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {regMode === 'staff' && state.staff.map(s => (
                    <div key={s.id} className="p-6 bg-white border border-emerald-50 rounded-3xl flex justify-between items-center shadow-sm">
                      <p className="text-sm font-black text-emerald-900">{s.name}</p>
                      <button onClick={() => deleteItem('staff', s.id)} className="text-red-300 hover:text-red-500"><i className="fa-solid fa-trash-can"></i></button>
                    </div>
                  ))}
                  {/* Subject and Class rendering logic follows similar pattern */}
                </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

