import React, { useState, useEffect } from 'react';
import { getState, saveState, getRole } from '../../services/dataStore';
import { AppState, StaffMember, Subject, ClassRoom, TimetableEntry, SystemLog, AttendanceRecord, LeaveRequest } from '../../types';
import { detectConflicts } from '../../services/coreEngine';
import { syncToCloud, fetchFromCloud } from '../../services/googleSheetsService';

const Label: React.FC<React.PropsWithChildren<{}>> = ({ children }) => (
  <label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest block mb-1.5 ml-1">{children}</label>
);

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [state, setState] = useState<AppState>(getState());
  const [activeTab, setActiveTab] = useState<'monitor' | 'registry' | 'time' | 'attn' | 'leaves' | 'sec' | 'sys'>('monitor');
  const [isSyncing, setIsSyncing] = useState(false);
  const userRole = getRole();

  // Component states
  const [regMode, setRegMode] = useState<'staff' | 'subject' | 'class'>('staff');
  const [selectedDay, setSelectedDay] = useState('Monday');
  const [gridClassId, setGridClassId] = useState('');
  const [editingSlot, setEditingSlot] = useState<string | null>(null);

  // Leave Form State
  const [leaveStaffId, setLeaveStaffId] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [leaveStart, setLeaveStart] = useState('');
  const [leaveEnd, setLeaveEnd] = useState('');

  // Persist state changes
  useEffect(() => {
    saveState(state);
    if (state.settings.cloudDbEnabled && state.settings.googleSheetWebAppUrl) {
      syncToCloud(state.settings.googleSheetWebAppUrl, state);
    }
  }, [state]);

  const addLog = (action: string) => {
    const newLog: SystemLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      user: userRole === 'principal' ? 'Principal' : 'Admin',
      action
    };
    setState(prev => ({ ...prev, logs: [newLog, ...prev.logs].slice(0, 50) }));
  };

  // --- REGISTRY HANDLERS ---
  const addStaff = () => {
    const name = prompt("Enter Staff Name:");
    if (!name) return;
    const newStaff: StaffMember = {
      id: 's' + Date.now(),
      name,
      email: name.toLowerCase().replace(' ', '.') + '@siddartha.edu',
      department: 'Pharmaceutics',
      specialization: [],
      assignedSubjects: [],
      isActive: true,
      availability: state.config.workingDays
    };
    setState(prev => ({ ...prev, staff: [...prev.staff, newStaff] }));
    addLog(`Added Staff: ${name}`);
  };

  const addSubject = () => {
    const name = prompt("Enter Subject Name:");
    const code = prompt("Enter Subject Code:");
    if (!name || !code) return;
    setState(prev => ({ ...prev, subjects: [...prev.subjects, { id: 'sub' + Date.now(), name, code, department: 'Pharmacy' }] }));
    addLog(`Added Subject: ${name}`);
  };

  const addClass = () => {
    const name = prompt("Enter Class Name:");
    const section = prompt("Enter Section:");
    if (!name || !section) return;
    setState(prev => ({ ...prev, classes: [...prev.classes, { id: 'c' + Date.now(), name, section }] }));
    addLog(`Added Class: ${name}`);
  };

  const deleteItem = (type: 'staff' | 'subject' | 'class', id: string) => {
    if (!confirm("Are you sure? This may impact timetables.")) return;
    setState(prev => ({
      ...prev,
      staff: type === 'staff' ? prev.staff.filter(i => i.id !== id) : prev.staff,
      subjects: type === 'subject' ? prev.subjects.filter(i => i.id !== id) : prev.subjects,
      classes: type === 'class' ? prev.classes.filter(i => i.id !== id) : prev.classes,
    }));
    addLog(`Deleted ${type} record`);
  };

  // --- ATTENDANCE HANDLERS ---
  const markAttendance = (staffId: string) => {
    const today = new Date().toISOString().split('T')[0];
    const isAlreadyMarked = state.attendance.some(a => a.staffId === staffId && a.date === today);
    if (isAlreadyMarked) return;

    const record: AttendanceRecord = {
      id: Date.now().toString(),
      staffId,
      date: today,
      timestamp: new Date().toLocaleTimeString(),
      status: 'Present'
    };
    setState(prev => ({ ...prev, attendance: [...prev.attendance, record] }));
    addLog(`Attendance Marked: ${state.staff.find(s => s.id === staffId)?.name}`);
  };

  // --- LEAVE HANDLERS ---
  const handleApplyLeave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!leaveStaffId || !leaveStart || !leaveEnd || !leaveReason) return alert("Fill all fields");
    const newLeave: LeaveRequest = {
      id: 'L' + Date.now(),
      staffId: leaveStaffId,
      startDate: leaveStart,
      endDate: leaveEnd,
      reason: leaveReason,
      status: 'Pending',
      requestDate: new Date().toLocaleDateString()
    };
    setState(prev => ({ ...prev, leaves: [newLeave, ...prev.leaves] }));
    addLog(`Leave applied: ${state.staff.find(s => s.id === leaveStaffId)?.name}`);
    setLeaveReason(''); setLeaveStaffId('');
    alert("Leave application sent to Principal.");
  };

  // --- TIMETABLE HANDLERS ---
  const handleAssignSlot = (slotId: string, facultyId: string, subjectId: string) => {
    if (!gridClassId) return;
    const newEntry: TimetableEntry = { id: Date.now().toString(), day: selectedDay, slotId, classId: gridClassId, facultyId, subjectId, type: 'Lecture' };
    const tempEntries = [...state.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId)), newEntry];
    const { conflicts } = detectConflicts(tempEntries);
    if (conflicts.length > 0 && !confirm(`Conflict: ${conflicts[0].description}. Save anyway?`)) return;
    setState(prev => ({ ...prev, timetable: tempEntries }));
    setEditingSlot(null);
    addLog(`Updated Timetable: ${selectedDay} @ ${slotId}`);
  };

  // --- SECURITY / SETTINGS ---
  const updateSettings = (key: string, value: any) => {
    setState(prev => ({ ...prev, settings: { ...prev.settings, [key]: value } }));
  };

  const handleCloudPush = async () => {
    if (!state.settings.googleSheetWebAppUrl) return alert("No URL set");
    setIsSyncing(true);
    const ok = await syncToCloud(state.settings.googleSheetWebAppUrl, state);
    if (ok) addLog("Cloud Push Success");
    setIsSyncing(false);
    alert(ok ? "Push Complete" : "Push Failed");
  };

  const handleCloudPull = async () => {
    if (!state.settings.googleSheetWebAppUrl) return alert("No URL set");
    if (!confirm("Overwrite local data?")) return;
    setIsSyncing(true);
    const data = await fetchFromCloud(state.settings.googleSheetWebAppUrl);
    if (data) { setState(data); saveState(data); addLog("Cloud Pull Success"); window.location.reload(); }
    setIsSyncing(false);
  };

  const allTabs = [
    { id: 'monitor', icon: 'fa-chart-line', label: 'Monitor' },
    { id: 'registry', icon: 'fa-address-book', label: 'Registry' },
    { id: 'time', icon: 'fa-calendar-check', label: 'Timetable' },
    { id: 'attn', icon: 'fa-clipboard-user', label: 'Attendance' },
    { id: 'leaves', icon: 'fa-calendar-day', label: 'Leaves' },
    { id: 'sec', icon: 'fa-shield-halved', label: 'Security', principal: true },
    { id: 'sys', icon: 'fa-sliders', label: 'System', principal: true }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8">
      {/* Sidebar */}
      <aside className="lg:w-64 space-y-4">
        <div className="p-6 glass rounded-3xl border-emerald-100 shadow-xl">
          <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white mb-4">
            <i className={`fa-solid ${userRole === 'principal' ? 'fa-crown' : 'fa-user-shield'}`}></i>
          </div>
          <h2 className="text-lg font-black text-emerald-900 uppercase tracking-tighter">{userRole} core</h2>
          <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest mt-1">v6.0 Enterprise</p>
        </div>
        <nav className="space-y-1">
          {allTabs.filter(t => userRole === 'principal' || !t.principal).map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`w-full flex items-center gap-4 px-5 py-3.5 rounded-2xl font-bold transition-all ${activeTab === tab.id ? 'bg-emerald-600 text-white shadow-lg' : 'text-emerald-800 hover:bg-emerald-50'}`}>
              <i className={`fa-solid ${tab.icon} w-5`}></i>
              <span className="text-[9px] uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
          <button onClick={onLogout} className="w-full flex items-center gap-4 px-5 py-3.5 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-6"><i className="fa-solid fa-power-off w-5"></i><span className="text-[9px] uppercase tracking-widest">Logout</span></button>
        </nav>
      </aside>

      {/* Main Content */}
