    const code = prompt("Enter Code:");
    if (!name || !code) return;
    setState(prev => ({ ...prev, subjects: [...prev.subjects, { id: 'sub' + Date.now(), name, code, department: 'Pharmacy' }] }));
    addLog(`Added Subject: ${name}`);
  };

  const addClass = () => {
    const name = prompt("Enter Class Name:");
    const section = prompt("Enter Section:");
    if (!name || !section) return;
    setState(prev => ({ ...prev, classes: [...prev.classes, { id: 'c' + Date.now(), name, section }] }));
    addLog(`Added Class: ${name}`);
  };

  const deleteItem = (type: 'staff' | 'subject' | 'class', id: string) => {
    if (!confirm("Are you sure?")) return;
    setState(prev => ({
      ...prev,
      staff: type === 'staff' ? prev.staff.filter(i => i.id !== id) : prev.staff,
      subjects: type === 'subject' ? prev.subjects.filter(i => i.id !== id) : prev.subjects,
      classes: type === 'class' ? prev.classes.filter(i => i.id !== id) : prev.classes,
    }));
    addLog(`Deleted ${type} record`);
  };

  // --- ATTENDANCE ---
  const markAttendance = (staffId: string) => {
    const today = new Date().toISOString().split('T')[0];
    const exists = state.attendance.some(a => a.staffId === staffId && a.date === today);
    if (exists) return;
    const record: AttendanceRecord = { id: Date.now().toString(), staffId, date: today, timestamp: new Date().toLocaleTimeString(), status: 'Present' };
    setState(prev => ({ ...prev, attendance: [...prev.attendance, record] }));
    addLog(`Attendance: ${state.staff.find(s => s.id === staffId)?.name} present`);
  };

  // --- LEAVES ---
  const handleLeaveApply = (e: React.FormEvent) => {
    e.preventDefault();
    if (!leaveStaffId || !leaveStart || !leaveEnd || !leaveReason) return alert("Fill all fields");
    const req: LeaveRequest = { id: 'L' + Date.now(), staffId: leaveStaffId, startDate: leaveStart, endDate: leaveEnd, reason: leaveReason, status: 'Pending', requestDate: new Date().toLocaleDateString() };
    setState(prev => ({ ...prev, leaves: [req, ...prev.leaves] }));
    addLog(`Leave applied for ${state.staff.find(s => s.id === leaveStaffId)?.name}`);
    setLeaveReason(''); setLeaveStaffId(''); alert("Submitted for approval.");
  };

  // --- TIMETABLE ---
  const assignSlot = (slotId: string, fId: string, sId: string) => {
    const newE: TimetableEntry = { id: Date.now().toString(), day: selectedDay, slotId, classId: gridClassId, facultyId: fId, subjectId: sId, type: 'Lecture' };
    const temp = [...state.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId)), newE];
    const { conflicts } = detectConflicts(temp);
    if (conflicts.length > 0 && !confirm(conflicts[0].description + " Continue?")) return;
    setState(prev => ({ ...prev, timetable: temp }));
    setEditingSlot(null);
    addLog(`Updated ${selectedDay} timetable`);
  };

  const clearSlot = (slotId: string) => {
    setState(prev => ({ ...prev, timetable: prev.timetable.filter(e => !(e.day === selectedDay && e.slotId === slotId && e.classId === gridClassId)) }));
  };

  // --- SYSTEM & SECURITY ---
  const updateSettings = (k: string, v: any) => setState(prev => ({ ...prev, settings: { ...prev.settings, [k]: v } }));

  const handlePush = async () => {
    if (!state.settings.googleSheetWebAppUrl) return alert("URL Missing");
    setIsSyncing(true);
    const ok = await syncToCloud(state.settings.googleSheetWebAppUrl, state);
    setIsSyncing(false); alert(ok ? "Cloud Sync Successful" : "Sync Failed");
  };

  const handlePull = async () => {
    if (!state.settings.googleSheetWebAppUrl) return alert("URL Missing");
    if (!confirm("Overwrite local data?")) return;
    setIsSyncing(true);
    const data = await fetchFromCloud(state.settings.googleSheetWebAppUrl);
    if (data) { setState(data); saveState(data); alert("Data Refreshed"); window.location.reload(); }
    setIsSyncing(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8">
      {/* Sidebar Navigation */}
      <aside className="lg:w-64 space-y-4">
        <div className="p-6 glass rounded-[2rem] border-emerald-100 shadow-xl text-center">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-lg">
            <i className={`fa-solid ${userRole === 'principal' ? 'fa-crown' : 'fa-user-shield'}`}></i>
          </div>
          <h2 className="text-sm font-black text-emerald-900 uppercase tracking-tighter">{userRole} core</h2>
          <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-[0.2em] mt-1">Enterprise v6.0</p>
        </div>

        <nav className="space-y-1">
          {[
            { id: 'monitor', icon: 'fa-chart-line', label: 'Monitor' },
            { id: 'registry', icon: 'fa-address-book', label: 'Registry' },
            { id: 'time', icon: 'fa-calendar-check', label: 'Timetable' },
            { id: 'attn', icon: 'fa-clipboard-user', label: 'Attendance' },
            { id: 'leaves', icon: 'fa-calendar-day', label: 'Leaves' },
            { id: 'sec', icon: 'fa-shield-halved', label: 'Security', p: true },
            { id: 'sys', icon: 'fa-sliders', label: 'System', p: true }
          ].filter(t => userRole === 'principal' || !t.p).map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === tab.id ? 'bg-emerald-600 text-white shadow-lg' : 'text-emerald-800 hover:bg-emerald-50'}`}>
              <i className={`fa-solid ${tab.icon} w-5`}></i>
              <span className="text-[9px] uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
          <button onClick={onLogout} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 mt-10 transition-all">
            <i className="fa-solid fa-power-off w-5"></i>
            <span className="text-[9px] uppercase tracking-widest">Logout</span>
          </button>
        </nav>
      </aside>

      {/* Content Container */}
      <main className="flex-grow glass rounded-[3rem] p-10 min-h-[800px] border-emerald-100 shadow-2xl overflow-hidden">

        {/* MONITOR */}
        {activeTab === 'monitor' && (
          <div className="space-y-10 animate-in fade-in">
            <h3 className="text-2xl font-black text-emerald-900 uppercase">Dashboard Monitor</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[
                { l: 'Faculty Registry', v: state.staff.length, c: 'emerald' },
                { l: 'Classes Configured', v: state.classes.length, c: 'blue' },
                { l: 'Pending Leaves', v: state.leaves.filter(l => l.status === 'Pending').length, c: 'amber' }
              ].map((s, i) => (
                <div key={i} className={`p-8 bg-${s.c}-50 rounded-3xl border border-${s.c}-100`}>
                  <Label>{s.l}</Label>
                  <p className={`text-4xl font-black text-${s.c}-900`}>{s.v}</p>
                </div>
              ))}
            </div>
            <div className="space-y-4">
              <Label>System Logs (Real-time)</Label>
              <div className="bg-slate-50 rounded-3xl p-6 h-64 overflow-y-auto border border-slate-100 text-[11px] font-bold">
                {state.logs.map(log => (
                  <div key={log.id} className="flex justify-between py-2 border-b border-slate-200 last:border-0">
                    <span className="text-slate-400">{log.timestamp}</span>
                    <span className="text-emerald-900">{log.action}</span>
                    <span className="text-emerald-600 uppercase">{log.user}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* REGISTRY */}
        {activeTab === 'registry' && (
          <div className="space-y-8 animate-in fade-in">
            <div className="flex justify-between items-center">
              <div className="flex bg-slate-100 p-1 rounded-xl">
                {['staff', 'subject', 'class'].map(m => (
                  <button key={m} onClick={() => setRegMode(m as any)} className={`px-5 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${regMode === m ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}>{m}s</button>
                ))}
              </div>
              <button onClick={() => regMode === 'staff' ? addStaff() : regMode === 'subject' ? addSubject() : addClass()} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-emerald-200">Add {regMode}</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {(regMode === 'staff' ? state.staff : regMode === 'subject' ? state.subjects : state.classes).map((item: any) => (
                <div key={item.id} className="p-6 bg-white border border-slate-100 rounded-[2rem] flex justify-between items-center shadow-sm hover:shadow-md transition-all">
                  <div>
                    <p className="text-sm font-black text-emerald-900">{item.name}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{item.code || item.department || `Section ${item.section}`}</p>
                  </div>
                  <button onClick={() => deleteItem(regMode, item.id)} className="text-red-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can"></i></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* TIMETABLE */}
        {activeTab === 'time' && (
          <div className="space-y-8 animate-in fade-in">
            <div className="flex flex-col md:flex-row gap-6 items-end">
              <div className="flex-grow">
                <Label>Class Matrix Selection</Label>
                <select value={gridClassId} onChange={e => setGridClassId(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-[11px] font-bold text-emerald-900">
                  <option value="">Select Target Class...</option>
                  {state.classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.section})</option>)}
                </select>
              </div>
              <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                {state.config.workingDays.map(d => (
                  <button key={d} onClick={() => setSelectedDay(d)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${selectedDay === d ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-500'}`}>{d.substring(0,3)}</button>
                ))}
              </div>
            </div>
            {gridClassId ? (
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {state.config.timeSlots.map(slot => {
                  const entry = state.timetable.find(e => e.day === selectedDay && e.slotId === slot.id && e.classId === gridClassId);
                  if (slot.isBreak) return <div key={slot.id} className="p-6 bg-amber-50 rounded-3xl border border-amber-100 text-center text-[9px] font-black text-amber-600 uppercase tracking-widest">{slot.label}</div>;
                  return (
                    <div key={slot.id} onClick={() => setEditingSlot(slot.id)} className={`p-8 rounded-[2.5rem] border transition-all cursor-pointer relative group ${entry ? 'bg-emerald-600 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-emerald-200'}`}>
                      <p className="text-[8px] font-black uppercase mb-1 opacity-50">{slot.label}</p>
                      {entry ? (
                        <>
                          <p className="text-xs font-black leading-tight mb-1">{state.subjects.find(s => s.id === entry.subjectId)?.name}</p>
                          <p className="text-[9px] font-bold opacity-80 uppercase">{state.staff.find(s => s.id === entry.facultyId)?.name}</p>
                          <button onClick={(e) => { e.stopPropagation(); clearSlot(slot.id); }} className="absolute top-4 right-4 text-white/50 hover:text-white"><i className="fa-solid fa-xmark"></i></button>
                        </>
                      ) : <p className="text-[9px] font-black text-slate-200">Unallocated</p>}
                      {editingSlot === slot.id && (
                        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-emerald-950/40 backdrop-blur-sm p-4" onClick={e => {e.stopPropagation(); setEditingSlot(null);}}>
                          <div className="bg-white rounded-[3rem] p-10 w-full max-w-sm shadow-2xl" onClick={e => e.stopPropagation()}>
                            <h4 className="text-xl font-black text-emerald-900 mb-8 uppercase">Slot Allocation</h4>
                            <div className="space-y-6">
                              <div><Label>Select Faculty</Label>
                                <select id={`f-${slot.id}`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-xs font-bold">
                                  {state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                </select>
                              </div>
                              <div><Label>Select Subject</Label>
                                <select id={`s-${slot.id}`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-xs font-bold">
                                  {state.subjects.map(s => <option key={s.id} value={s.id}>{s.name} ({s.code})</option>)}
                                </select>
                              </div>
                              <button onClick={() => assignSlot(slot.id, (document.getElementById(`f-${slot.id}`) as any).value, (document.getElementById(`s-${slot.id}`) as any).value)} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-emerald-200">Update Grid</button>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            ) : <div className="p-32 text-center text-slate-200 font-black uppercase text-xs">Select class to access grid</div>}
          </div>
        )}

        {/* ATTENDANCE */}
        {activeTab === 'attn' && (
          <div className="space-y-10 animate-in fade-in">
            <h3 className="text-2xl font-black text-emerald-900 uppercase">Faculty Presence Matrix</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {state.staff.map(s => {
                const today = new Date().toISOString().split('T')[0];
                const marked = state.attendance.some(a => a.staffId === s.id && a.date === today);
                return (
                  <div key={s.id} className={`p-8 rounded-[2.5rem] border flex justify-between items-center transition-all ${marked ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                    <div>
                      <p className="text-sm font-black text-emerald-900">{s.name}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{s.department}</p>
                    </div>
                    <button onClick={() => markAttendance(s.id)} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${marked ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-100 text-slate-300 hover:text-emerald-600'}`}>
                      <i className="fa-solid fa-check"></i>
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* LEAVES */}
        {activeTab === 'leaves' && (
          <div className="space-y-12 animate-in fade-in">
            <div className="bg-white p-10 rounded-[3rem] border border-emerald-100 shadow-sm">
              <h4 className="text-sm font-black text-emerald-900 uppercase mb-8">Leave Application Hub</h4>
              <form onSubmit={handleLeaveApply} className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-6">
                  <div><Label>Applying Staff Member</Label>
                    <select value={leaveStaffId} onChange={e => setLeaveStaffId(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-xs font-bold text-emerald-900">
                      <option value="">Choose Faculty Identity...</option>
                      {state.staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div><Label>Commencement</Label><input type="date" value={leaveStart} onChange={e => setLeaveStart(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-[11px] font-bold" /></div>
                    <div><Label>Conclusion</Label><input type="date" value={leaveEnd} onChange={e => setLeaveEnd(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl text-[11px] font-bold" /></div>
                  </div>
                </div>
                <div className="space-y-6">
                  <div><Label>Reason / Justification</Label>
                    <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Provide detailed justification for leave..." className="w-full h-24 p-4 bg-slate-50 border border-slate-100 rounded-2xl text-xs font-bold focus:outline-emerald-500 resize-none" />
                  </div>
                  <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-emerald-200">Submit for Verification</button>
                </div>
              </form>
            </div>
            {userRole === 'principal' && (
              <div className="space-y-6">
                <h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest">Authorization Queue</h4>
                {state.leaves.filter(l => l.status === 'Pending').map(req => (
                  <div key={req.id} className="p-8 bg-white border border-slate-100 rounded-[2.5rem] flex flex-col md:flex-row justify-between items-center gap-6 shadow-sm">
                    <div className="flex-grow">
                      <p className="text-lg font-black text-emerald-900">{state.staff.find(s => s.id === req.staffId)?.name}</p>
                      <p className="text-xs font-bold text-slate-500 italic mb-2">"{req.reason}"</p>
                      <p className="text-[10px] font-black text-emerald-600 uppercase">{req.startDate} to {req.endDate}</p>
                    </div>
                    <div className="flex gap-4">
                      <button onClick={() => { setState(prev => ({ ...prev, leaves: prev.leaves.map(l => l.id === req.id ? {...l, status: 'Approved'} : l) })); addLog(`Approved Leave ${req.id}`); }} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-lg">Accept</button>
                      <button onClick={() => { setState(prev => ({ ...prev, leaves: prev.leaves.map(l => l.id === req.id ? {...l, status: 'Rejected'} : l) })); addLog(`Rejected Leave ${req.id}`); }} className="px-6 py-3 bg-white border border-red-100 text-red-500 rounded-2xl text-[9px] font-black uppercase tracking-widest">Reject</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* SECURITY */}
        {activeTab === 'sec' && userRole === 'principal' && (
          <div className="space-y-12 animate-in fade-in">
            <h3 className="text-2xl font-black text-emerald-900 uppercase">Core Access & Persistence Hub</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 p-10 bg-white border border-emerald-100 rounded-[3rem]">
              <div className="space-y-6">
                <h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest">Principal Identity</h4>
                <div className="space-y-3"><Label>Username</Label><input type="text" value={state.settings.principalUsername} onChange={e => updateSettings('principalUsername', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
                <div className="space-y-3"><Label>Keyphrase</Label><input type="password" value={state.settings.principalPassword} onChange={e => updateSettings('principalPassword', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
              </div>
              <div className="space-y-6">
                <h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest">Admin Identity</h4>
                <div className="space-y-3"><Label>Username</Label><input type="text" value={state.settings.adminUsername} onChange={e => updateSettings('adminUsername', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
                <div className="space-y-3"><Label>Keyphrase</Label><input type="password" value={state.settings.adminPassword} onChange={e => updateSettings('adminPassword', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
              </div>
            </div>
            <div className="p-10 bg-white border border-emerald-100 rounded-[3rem] space-y-6">
              <div className="flex justify-between items-center"><h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest">Google Auth Bridge</h4>
                <button onClick={() => updateSettings('googleLoginEnabled', !state.settings.googleLoginEnabled)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase ${state.settings.googleLoginEnabled ? 'bg-emerald-600 text-white' : 'bg-slate-100'}`}>{state.settings.googleLoginEnabled ? 'Active' : 'Disabled'}</button>
              </div>
              {state.settings.googleLoginEnabled && <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div><Label>Client ID</Label><input type="text" value={state.settings.googleClientId} onChange={e => updateSettings('googleClientId', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-[10px] font-mono" /></div>
                <div><Label>Whitelisted Emails</Label><input type="text" value={state.settings.approvedEmails.join(', ')} onChange={e => updateSettings('approvedEmails', e.target.value.split(',').map(s => s.trim()))} className="w-full p-4 bg-slate-50 border rounded-2xl text-[10px] font-mono" /></div>
              </div>}
            </div>
            <div className="p-10 bg-white border border-emerald-100 rounded-[3rem] space-y-6">
              <h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest">Global Sync Engine</h4>
              <Label>Google Sheet Apps Script Endpoint</Label>
              <input type="text" value={state.settings.googleSheetWebAppUrl} onChange={e => updateSettings('googleSheetWebAppUrl', e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl text-[11px] font-mono" />
              <div className="flex gap-4"><button onClick={handlePush} className="flex-grow py-4 bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-lg">Push Instance</button>
                <button onClick={handlePull} className="flex-grow py-4 bg-white border border-emerald-100 text-emerald-600 rounded-2xl text-[10px] font-black uppercase">Pull Instance</button>
              </div>
            </div>
          </div>
        )}

        {/* SYSTEM */}
        {activeTab === 'sys' && userRole === 'principal' && (
          <div className="space-y-12 animate-in fade-in">
            <h3 className="text-2xl font-black text-emerald-900 uppercase">Institutional Architecture</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 p-10 bg-white border border-emerald-100 rounded-[3rem]">
              <div className="space-y-6">
                <Label>Operational Days</Label>
                <div className="grid grid-cols-2 gap-3">
                  {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'].map(day => (
                    <button key={day} onClick={() => { const next = state.config.workingDays.includes(day) ? state.config.workingDays.filter(d => d !== day) : [...state.config.workingDays, day]; setState({...state, config: {...state.config, workingDays: next}}); }} className={`p-4 rounded-xl text-[9px] font-black uppercase transition-all border ${state.config.workingDays.includes(day) ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>{day}</button>
                  ))}
                </div>
              </div>
              <div className="space-y-6">
                <div><Label>Academic Session</Label><input type="text" value={state.config.academicYear} onChange={e => setState({...state, config: {...state.config, academicYear: e.target.value}})} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
                <div><Label>Current Term</Label><input type="text" value={state.config.term} onChange={e => setState({...state, config: {...state.config, term: e.target.value}})} className="w-full p-4 bg-slate-50 border rounded-2xl text-xs font-bold" /></div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;

import { TimetableEntry, AnalysisResult, AppState } from "../types";
import { getState } from "./dataStore";

/**
 * Institutional Logic: Conflict Detection
 * Checks for faculty double-booking or classroom overlaps.
 */
export const detectConflicts = (entries: TimetableEntry[]) => {
  const conflicts: { type: string; description: string; severity: string }[] = [];
  const facultyMap = new Map<string, TimetableEntry>();
  const classMap = new Map<string, TimetableEntry>();
  const state = getState();

  entries.forEach(e => {
    const facultyKey = `${e.day}-${e.slotId}-${e.facultyId}`;
    const classKey = `${e.day}-${e.slotId}-${e.classId}`;

    if (facultyMap.has(facultyKey)) {
      const existing = facultyMap.get(facultyKey)!;
      // If it's the same entry ID, skip (it's the one we're editing)
      if (existing.id !== e.id) {
        const faculty = state.staff.find(s => s.id === e.facultyId);
        const c1 = state.classes.find(c => c.id === existing.classId)?.name;
        const c2 = state.classes.find(c => c.id === e.classId)?.name;
        conflicts.push({
          type: "Faculty Conflict",
          description: `${faculty?.name || 'Faculty'} is already assigned to ${c1} during this slot. Overlap with ${c2}.`,
          severity: "High"
        });
      }
    }
    facultyMap.set(facultyKey, e);

    if (classMap.has(classKey)) {
      const existing = classMap.get(classKey)!;
      if (existing.id !== e.id) {
        const cName = state.classes.find(c => c.id === e.classId)?.name;
        conflicts.push({
          type: "Class Overlap",
          description: `${cName} is already assigned a subject in this slot.`,
          severity: "Medium"
        });
      }
    }
    classMap.set(classKey, e);
  });

  return { conflicts };
};

/**
 * Institutional Logic: Substitution Finder
 * Deterministic matching based on department and active status.
 */
export const suggestSubstitution = async (subjectName: string, reason: string) => {
  const state = getState();
  const subject = state.subjects.find(s => s.name === subjectName);

  const sameDept = state.staff.filter(s => s.isActive && (subject ? s.department === subject.department : true));
  const candidate = sameDept[0] || state.staff.find(s => s.isActive);

  // Simulation of processing time
  await new Promise(r => setTimeout(r, 200));

  if (!candidate) return "No staff available in current registry.";

  return `System Match: ${candidate.name} (${candidate.department}). Verification: Departmental alignment confirmed. Replacement trigger: ${reason}.`;
};

/**
 * Institutional Logic: Resource Validator
 * Scans institutional assets based on pattern signatures for domain authenticity.
 */
export const verifyResource = async (url: string): Promise<AnalysisResult> => {
  // Simulation of verification handshake
  await new Promise(r => setTimeout(r, 400));

  const lowerUrl = url.toLowerCase();
  const isInstitutional = lowerUrl.includes('siddartha') || lowerUrl.includes('scops') || lowerUrl.includes('bolt.host');
  const isEdu = lowerUrl.includes('.edu') || lowerUrl.includes('.ac.in') || lowerUrl.includes('.gov');

  let summary = "";
  let confidence = "Standard";

  if (isInstitutional) {
    summary = `Domain Validation Successful: Institutional asset detected. \n\nResource [${url}] matches KVSR Siddhartha College architectural signatures. Authenticity verified via local gateway protocols. Access to this core asset is permitted.`;
    confidence = "High";
  } else if (isEdu) {
    summary = `Academic Validation: The resource at ${url} is confirmed as a global academic domain. Protocol: TLD Signature Match. Suitable for institutional referencing.`;
    confidence = "Verified";
  } else {
    summary = `Network Result: ${url} identified as an external third-party resource. No institutional metadata detected in headers.`;
  }

  return {
    summary,
    sources: [
      { uri: url, title: `Validated ${confidence} Resource` }
    ]
  };
};

